        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animTurn);

        // Once both turn frames finish: flip horizontally, resume patrol
        if (animTurn.isAnimationFinished(stateTimer))
