    private void faceTarget()
    {
        if (pablo.getX() > getX())
            direction = 1f;
        else
            direction = -1f;
        faceDirection(direction);
    }

    private void enterState(HuskHornheadState next)
    {
        state = next;
        stateTimer = 0f;
        elapsedTime = 0f;
    }
}

// HuskWarrior.java
package pablo.entities.enemies.huskWarrior;

import com.badlogic.gdx.graphics.g2d.Animation;
import com.badlogic.gdx.scenes.scene2d.Stage;
import pablo.entities.enemies.Enemy;
import pablo.entities.player.Pablo;
import pablo.framework.BaseActor;

public class HuskWarrior extends Enemy
{
    private static final String PATH = "assets/HuskWarrior/";

    // Movement
    private static final float PATROL_SPEED          = 50f;
    private static final float IDLE_DURATION         = 0.8f;
    private static final float RECOIL_SPEED          = 70f;      // backward push on block

    // Shield timings
    private static final float SHIELD_ANTICIPATE_DUR = 0.040f;
    private static final float SHIELD_FRONT_IMPACT   = 0.050f;   // shield(front)1 hold
    private static final float SHIELD_FRONT_HOLD     = 0.300f;   // shield(front)2 hold + recoil
    private static final float SHIELD_TOP_DUR        = 0.166f;   // top1+top2 combined
    private static final float SHIELD_TOP_BUMP_IMPACT= 0.050f;
    private static final float SHIELD_TOP_BUMP_HOLD  = 0.150f;

    // Attack timings
    private static final float WINDUP_INTRO_DUR      = 3 * 0.066f; // attack1-3 = 0.198f
    private static final float WINDUP_TOTAL_DUR      = WINDUP_INTRO_DUR + 0.150f; // + hold attack4
    private static final float STRIKE1_WINDOW        = 0.080f;   // attack5-6
    private static final float STRIKE2_WINDOW        = 0.050f;   // attack7
    private static final float STRIKE3_WINDOW        = 0.080f;   // attack8
    private static final float STRIKE_GAP            = 0.120f;   // cooldown between strikes
    private static final float STRIKE2_START         = STRIKE1_WINDOW + STRIKE_GAP;
    private static final float STRIKE3_START         = STRIKE2_START + STRIKE2_WINDOW + STRIKE_GAP;
    private static final float ATTACK_TOTAL_DUR      = STRIKE3_START + STRIKE3_WINDOW;
    private static final float ATTACK_COOLDOWN_DUR   = 0.200f;

    // Pogo bounce given to Pablo on top block
    private static final float POGO_BOUNCE_SPEED     = 380f;

    // Death
    private static final float HIT_STOP_DURATION    = 0.100f;
    private static final float DEATH_KNOCKBACK_X    = 320f;
    private static final float DEATH_KNOCKBACK_Y    = 380f;
    private static final float DEATH_GRAVITY        = 1400f;
    private static final float MAX_FALL_SPEED       = 1200f;
    private static final float SPIN_SPEED           = 460f;
    private static final float LAND_TUMBLE_DURATION = 7 * 0.066f;

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------
    private HuskWarriorState state;
    private float stateTimer;

    // -------------------------------------------------------------------------
    // Death
    // -------------------------------------------------------------------------
    private float hitStopTimer;
    private float deathKnockbackDir;
    private float spinDir;

    // -------------------------------------------------------------------------
    // Combat — per-strike hit flags reset on enterState
    // -------------------------------------------------------------------------
    private boolean hit1Landed, hit2Landed, hit3Landed;

    // -------------------------------------------------------------------------
    // Player reference
    // -------------------------------------------------------------------------
    private Pablo pablo;

    // -------------------------------------------------------------------------
    // Animations
    // -------------------------------------------------------------------------
    private Animation animIdle;
    private Animation animWalk;
    private Animation animTurn;
    private Animation animShieldAnticipate;
    private Animation animShieldFrontImpact; // shield(front)1
    private Animation animShieldFrontHold;   // shield(front)2
    private Animation animShieldTop;         // shield(top)1+2
    private Animation animShieldTopImpact;   // shield(topBump)1
    private Animation animShieldTopHold;     // shield(topBump)2
    private Animation animWindupIntro;       // attack1-3
    private Animation animWindupHold;        // attack4 held
    private Animation animAttackStrikes;     // attack5-8
    private Animation animDeathAir;
    private Animation animDeathLand;
    private Animation animDeathCorpse;

    // Detection
    private static final float DETECTION_RADIUS      = 220f;

    public HuskWarrior(float x, float y, Stage stage, Pablo pablo)
    {
        super(x, y, stage);
        this.pablo = pablo;

        health = 16; // 4 unshielded hits from Pablo (4 dmg each)

        animIdle = loadAnimationFromFiles(new String[]{
                PATH+"idle1.png", PATH+"idle2.png", PATH+"idle3.png",
                PATH+"idle4.png", PATH+"idle5.png", PATH+"idle6.png"
        }, 0.083f, true);

        animWalk = loadAnimationFromFiles(new String[]{
                PATH+"walk1.png", PATH+"walk2.png", PATH+"walk3.png",
                PATH+"walk4.png", PATH+"walk5.png", PATH+"walk6.png",
                PATH+"walk7.png"
        }, 0.083f, true);

        animTurn = loadAnimationFromFiles(new String[]{
                PATH+"turn1.png", PATH+"turn2.png"
        }, 0.083f, false);

        // Shield anticipate: single frame, 40ms
        animShieldAnticipate = loadAnimationFromFiles(new String[]{
                PATH+"shield(anticipate).png"
        }, 0.040f, false);

        // Shield front: impact frame, then hold frame (separate anims for clean phasing)
        animShieldFrontImpact = loadAnimationFromFiles(new String[]{
                PATH+"shield(front)1.png"
        }, 0.050f, false);

        animShieldFrontHold = loadAnimationFromFiles(new String[]{
                PATH+"shield(front)2.png"
        }, 1f, true);

        // Shield top: raise sequence plays once
        animShieldTop = loadAnimationFromFiles(new String[]{
                PATH+"shield(top)1.png", PATH+"shield(top)2.png"
        }, 0.083f, false);

        animShieldTopImpact = loadAnimationFromFiles(new String[]{
                PATH+"shield(topBump)1.png"
        }, 0.050f, false);

        animShieldTopHold = loadAnimationFromFiles(new String[]{
                PATH+"shield(topBump)2.png"
        }, 1f, true);

        // Windup: attack1-3 intro, then attack4 held (same split as HuskHornhead anticipate)
        animWindupIntro = loadAnimationFromFiles(new String[]{
                PATH+"attack1.png", PATH+"attack2.png", PATH+"attack3.png"
        }, 0.066f, false);

        animWindupHold = loadAnimationFromFiles(new String[]{
                PATH+"attack4.png"
        }, 1f, true);

        // Three strikes: average frame duration (~52ms); hitboxes spawned by stateTimer
        animAttackStrikes = loadAnimationFromFiles(new String[]{
                PATH+"attack5.png", PATH+"attack6.png",
                PATH+"attack7.png", PATH+"attack8.png"
        }, 0.052f, false);

        animDeathAir = loadAnimationFromFiles(new String[]{
                PATH+"death(air).png"
        }, 1f, true);

        animDeathLand = loadAnimationFromFiles(new String[]{
                PATH+"death(land)1.png", PATH+"death(land)2.png",
                PATH+"death(land)3.png", PATH+"death(land)4.png",
                PATH+"death(land)5.png", PATH+"death(land)6.png",
                PATH+"death(land)7.png"
        }, 0.066f, false);

        animDeathCorpse = loadAnimationFromFiles(new String[]{
                PATH+"death(land)8.png"
        }, 1f, true);

        setBoundaryRectangle();

        belowSensor = new BaseActor(0, 0, stage);
        belowSensor.loadTexture("assets/white.png");
        belowSensor.setSize(getWidth() - 8f, 6f);
        belowSensor.setBoundaryRectangle();
        belowSensor.setVisible(false);

        edgeSensor = new BaseActor(0, 0, stage);
        edgeSensor.loadTexture("assets/white.png");
        edgeSensor.setSize(6f, 6f);
        edgeSensor.setBoundaryRectangle();
        edgeSensor.setVisible(false);

        // Posiziona i sensori subito per il primo frame
        updateSensorPositions();

        enterState(HuskWarriorState.IDLE);
    }

    @Override
    public void act(float dt)
    {
        super.act(dt);

        if (!canUpdateAI() && !isInDeathSequence())
            return;

        if (state == HuskWarriorState.HIT_STOP)
        {
            hitStopTimer -= dt;
            if (hitStopTimer <= 0f)
                launchDeath();
            return;
        }

        stateTimer += dt;

        switch (state)
        {
            case IDLE:              tickIdle(dt);            break;
            case PATROL:            tickPatrol(dt);          break;
            case TURNING:           tickTurning(dt);         break;
            case SHIELD_ANTICIPATE: tickShieldAnticipate(dt);break;
            case SHIELD_FRONT:      tickShieldFront(dt);     break;
            case SHIELD_TOP:        tickShieldTop(dt);       break;
            case SHIELD_TOP_BUMP:   tickShieldTopBump(dt);   break;
            case ATTACK_WINDUP:     tickAttackWindup(dt);    break;
            case ATTACKING:         tickAttacking(dt);       break;
            case ATTACK_COOLDOWN:   tickAttackCooldown(dt);  break;
            case DEAD_AIR:          tickDeadAir(dt);         break;
            case DEAD_LAND:         tickDeadLand(dt);        break;
        }
    }

    private void tickIdle(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animIdle);
        faceDirection(direction);

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (stateTimer >= IDLE_DURATION)
            enterState(HuskWarriorState.PATROL);
    }

    private void tickPatrol(float dt)
    {
        applyGravity(dt);
        updateSensorPositions();

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (isOnGround() && !edgeAheadHasground())
        {
            enterState(HuskWarriorState.TURNING);
            return;
        }

        velocityVec.x = direction * PATROL_SPEED;
        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animWalk);
        syncFacingToHorizontalMovement();
    }

    private void tickTurning(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animTurn);

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (animTurn.isAnimationFinished(stateTimer))
        {
            flip();
            enterState(HuskWarriorState.PATROL);
        }
    }

    private void tickShieldAnticipate(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animShieldAnticipate);
        faceDirection(direction);

        if (stateTimer >= SHIELD_ANTICIPATE_DUR)
            enterState(HuskWarriorState.SHIELD_FRONT);
    }

    private void tickShieldFront(float dt)
    {
        applyGravity(dt);
        updateSensorPositions();

        float total = SHIELD_FRONT_IMPACT + SHIELD_FRONT_HOLD;

        if (stateTimer < SHIELD_FRONT_IMPACT)
        {
            // Impact frame — planted
            setAnimation(animShieldFrontImpact);
            velocityVec.x = 0;
        }
        else
        {
            // Hold frame — recoil pushback away from Pablo
            setAnimation(animShieldFrontHold);
            float recoilDir;

            if (pablo.getX() > getX())
                recoilDir = -1f;
            else
                recoilDir = 1f;
            velocityVec.x   = recoilDir * RECOIL_SPEED;
        }

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        syncFacingToHorizontalMovement();

        if (stateTimer >= total)
            enterState(HuskWarriorState.ATTACK_WINDUP);
    }

    private void tickShieldTop(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animShieldTop);
        faceDirection(direction);

        if (stateTimer >= SHIELD_TOP_DUR)
            enterState(HuskWarriorState.SHIELD_TOP_BUMP);
    }

    private void tickShieldTopBump(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        float total = SHIELD_TOP_BUMP_IMPACT + SHIELD_TOP_BUMP_HOLD;

        if (stateTimer < SHIELD_TOP_BUMP_IMPACT)
            setAnimation(animShieldTopImpact);
        else
            setAnimation(animShieldTopHold);

        faceDirection(direction);

        if (stateTimer >= total)
            enterState(HuskWarriorState.PATROL);
    }

    private void tickAttackWindup(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        if (stateTimer < WINDUP_INTRO_DUR)
            setAnimation(animWindupIntro); // attack1-3 at 66ms each
        else
            setAnimation(animWindupHold);  // attack4 held for 150ms

        faceDirection(direction);

        if (stateTimer >= WINDUP_TOTAL_DUR)
            enterState(HuskWarriorState.ATTACKING);
    }

    private void tickAttacking(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animAttackStrikes);
        faceDirection(direction);

        boolean inStrike1 = stateTimer < STRIKE1_WINDOW;
        boolean inStrike2 = stateTimer >= STRIKE2_START && stateTimer < (STRIKE2_START + STRIKE2_WINDOW);
        boolean inStrike3 = stateTimer >= STRIKE3_START && stateTimer < (STRIKE3_START + STRIKE3_WINDOW);
        attackHitboxActive = inStrike1 || inStrike2 || inStrike3;
        syncAttackHitbox();

        // Strike 1 — attack5+6 window
        if (inStrike1 && !hit1Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit1Landed = true;
        }

        // Strike 2 — attack7 window
        if (inStrike2 && !hit2Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit2Landed = true;
        }

        // Strike 3 — attack8 window
        if (inStrike3 && !hit3Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit3Landed = true;
        }

        if (stateTimer >= ATTACK_TOTAL_DUR)
            enterState(HuskWarriorState.ATTACK_COOLDOWN);
    }

    private void tickAttackCooldown(float dt)
    {
        // Punish window: warrior rests, shield is DOWN, all hits land
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animIdle);
        faceDirection(direction);

        if (stateTimer >= ATTACK_COOLDOWN_DUR)
            enterState(HuskWarriorState.IDLE);
    }

    private void tickDeadAir(float dt)
    {
        velocityVec.y -= DEATH_GRAVITY * dt;
        velocityVec.y  = Math.max(velocityVec.y, -MAX_FALL_SPEED);

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animDeathAir);
        setRotation(getRotation() + spinDir * SPIN_SPEED * dt);
        syncFacingToHorizontalMovement();

        if (isOnGround())
        {
            velocityVec.set(0, 0);
            setRotation(0); // snap on impact
            enterState(HuskWarriorState.DEAD_LAND);
        }
    }

    private void tickDeadLand(float dt)
    {
        if (stateTimer < LAND_TUMBLE_DURATION)
        {
            // Frames 1-7: tumble with decelerating slide
            float progress   = stateTimer / LAND_TUMBLE_DURATION;
            float slideSpeed = 60f * (1f - progress);
            velocityVec.x = deathKnockbackDir * slideSpeed;
            moveBy(velocityVec.x * dt, 0);
            syncFacingToHorizontalMovement();
            setAnimation(animDeathLand);
        }
        else
        {
            // Frame 8: hold forever — no remove()
            velocityVec.set(0, 0);
            setAnimation(animDeathCorpse);
        }
    }

    @Override
    public void takeDamage(int amount)
    {
        // Ignore during death
        if (state == HuskWarriorState.HIT_STOP ||
                state == HuskWarriorState.DEAD_AIR   ||
                state == HuskWarriorState.DEAD_LAND)
            return;

        // Ignore during active combat (committed to attack)
        if (state == HuskWarriorState.ATTACK_WINDUP ||
                state == HuskWarriorState.ATTACKING)
            return;

        // Already in a shield state — ignore repeat hits
        if (state == HuskWarriorState.SHIELD_ANTICIPATE ||
                state == HuskWarriorState.SHIELD_FRONT    ||
                state == HuskWarriorState.SHIELD_TOP      ||
                state == HuskWarriorState.SHIELD_TOP_BUMP)
            return;

        // Blocking only active while patrolling — cooldown is the punish window
        boolean canBlock = (state == HuskWarriorState.IDLE    ||
                state == HuskWarriorState.PATROL   ||
                state == HuskWarriorState.TURNING);

        if (canBlock && isPogoFromAbove())
        {
            pablo.velocityVec.y = POGO_BOUNCE_SPEED; // bounce Pablo upward
            enterState(HuskWarriorState.SHIELD_TOP);
            return; // no damage
        }

        if (canBlock && isShieldFacingPablo())
        {
            enterState(HuskWarriorState.SHIELD_ANTICIPATE); // block → retaliate
            return; // no damage
        }

        // Unshielded hit (from behind, or during cooldown)
        health -= amount;

        if (health <= 0)
        {
            health = 0;
            if (pablo.getX() < getX())
                deathKnockbackDir = 1f;
            else
                deathKnockbackDir = -1f;
            spinDir           = deathKnockbackDir;
            hitStopTimer      = HIT_STOP_DURATION;
            spawnShieldProp();
            enterState(HuskWarriorState.HIT_STOP);
        }
    }

    private void launchDeath()
    {
        velocityVec.x = deathKnockbackDir * DEATH_KNOCKBACK_X;
        velocityVec.y = DEATH_KNOCKBACK_Y;
        enterState(HuskWarriorState.DEAD_AIR);
    }

    @Override
    public void onWallHit()
    {
        if (state == HuskWarriorState.PATROL)
            flip();
        // All other states: walls are ignored
    }

    private void spawnShieldProp()
    {
        // Shield flies opposite to knockback direction and arcs upward
        float shieldVelX = -deathKnockbackDir * 190f;
        float shieldVelY = 310f;
        float shieldSpin = deathKnockbackDir * 380f; // degrees/sec
        new ShieldProp(getX(), getY() + getHeight() * 0.5f,
                getStage(), shieldVelX, shieldVelY, shieldSpin);
    }

    // Returns true if the shield side of the warrior is the side Pablo is on
    private boolean isShieldFacingPablo()
    {
        float pabloCenterX = pablo.getX() + pablo.getWidth()  / 2f;
        float selfCenterX  = getX()       + getWidth()        / 2f;
        if (direction > 0)
            return pabloCenterX > selfCenterX;
        else
            return pabloCenterX < selfCenterX;
    }

    private boolean isInDetectionRange()
    {
        float selfX = getX() + getWidth() / 2f;
        float selfY = getY() + getHeight() / 2f;

        float pabloX = pablo.getX() + pablo.getWidth() / 2f;
        float pabloY = pablo.getY() + pablo.getHeight() / 2f;

        float dx = pabloX - selfX;
        float dy = pabloY - selfY;

        return dx * dx + dy * dy < DETECTION_RADIUS * DETECTION_RADIUS;
    }

    private void faceTarget()
    {
        if (pablo.getX() > getX())
            direction = 1f;
        else
            direction = -1f;
        faceDirection(direction);
    }

    // True when Pablo is falling from above the warrior's midpoint
    private boolean isPogoFromAbove()
    {
        float warriorMidY  = getY() + getHeight() * 0.5f;
        float pabloCenterY = pablo.getY() + pablo.getHeight() / 2f;
        return pabloCenterY > warriorMidY && pablo.velocityVec.y < 0;
    }

    private void enterState(HuskWarriorState next)
    {
        state       = next;
        stateTimer  = 0f;
        elapsedTime = 0f;
        hit1Landed  = false;
        hit2Landed  = false;
        hit3Landed  = false;
    }

    private boolean isInDeathSequence()
    {
        return state == HuskWarriorState.HIT_STOP ||
                state == HuskWarriorState.DEAD_AIR ||
                state == HuskWarriorState.DEAD_LAND;
    }

    // =========================================================================
    // Shield Prop — independent physics actor spawned at moment of death
    // =========================================================================
    private static class ShieldProp extends BaseActor
    {
        private float velX, velY;
        private float spinRate;
        private static final float GRAVITY = 1000f;

        ShieldProp(float x, float y, Stage stage, float velX, float velY, float spinRate)
        {
            super(x, y, stage);
            this.velX     = velX;
            this.velY     = velY;
            this.spinRate = spinRate;
            loadTexture("assets/HuskWarrior/death(shield).png");
            setBoundaryRectangle();
        }

        @Override
        public void act(float dt)
        {
            super.act(dt);
            velY -= GRAVITY * dt;
            moveBy(velX * dt, velY * dt);
            setRotation(getRotation() + spinRate * dt);
            if (getY() < -200f) remove(); // self-cleanup when off-screen
        }
    }
}

// HuskWarrior.java
package pablo.entities.enemies.huskWarrior;

import com.badlogic.gdx.graphics.g2d.Animation;
import com.badlogic.gdx.scenes.scene2d.Stage;
import pablo.entities.enemies.Enemy;
import pablo.entities.player.Pablo;
import pablo.framework.BaseActor;

public class HuskWarrior extends Enemy
{
    private static final String PATH = "assets/HuskWarrior/";

    // Movement
    private static final float PATROL_SPEED          = 50f;
    private static final float IDLE_DURATION         = 0.8f;
    private static final float RECOIL_SPEED          = 70f;      // backward push on block

    // Shield timings
    private static final float SHIELD_ANTICIPATE_DUR = 0.040f;
    private static final float SHIELD_FRONT_IMPACT   = 0.050f;   // shield(front)1 hold
    private static final float SHIELD_FRONT_HOLD     = 0.300f;   // shield(front)2 hold + recoil
    private static final float SHIELD_TOP_DUR        = 0.166f;   // top1+top2 combined
    private static final float SHIELD_TOP_BUMP_IMPACT= 0.050f;
    private static final float SHIELD_TOP_BUMP_HOLD  = 0.150f;

    // Attack timings
    private static final float WINDUP_INTRO_DUR      = 3 * 0.066f; // attack1-3 = 0.198f
    private static final float WINDUP_TOTAL_DUR      = WINDUP_INTRO_DUR + 0.150f; // + hold attack4
    private static final float STRIKE1_WINDOW        = 0.080f;   // attack5-6
    private static final float STRIKE2_WINDOW        = 0.050f;   // attack7
    private static final float STRIKE3_WINDOW        = 0.080f;   // attack8
    private static final float STRIKE_GAP            = 0.120f;   // cooldown between strikes
    private static final float STRIKE2_START         = STRIKE1_WINDOW + STRIKE_GAP;
    private static final float STRIKE3_START         = STRIKE2_START + STRIKE2_WINDOW + STRIKE_GAP;
    private static final float ATTACK_TOTAL_DUR      = STRIKE3_START + STRIKE3_WINDOW;
    private static final float ATTACK_COOLDOWN_DUR   = 0.200f;

    // Pogo bounce given to Pablo on top block
    private static final float POGO_BOUNCE_SPEED     = 380f;

    // Death
    private static final float HIT_STOP_DURATION    = 0.100f;
    private static final float DEATH_KNOCKBACK_X    = 320f;
    private static final float DEATH_KNOCKBACK_Y    = 380f;
    private static final float DEATH_GRAVITY        = 1400f;
    private static final float MAX_FALL_SPEED       = 1200f;
    private static final float SPIN_SPEED           = 460f;
    private static final float LAND_TUMBLE_DURATION = 7 * 0.066f;

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------
    private HuskWarriorState state;
    private float stateTimer;

    // -------------------------------------------------------------------------
    // Death
    // -------------------------------------------------------------------------
    private float hitStopTimer;
    private float deathKnockbackDir;
    private float spinDir;

    // -------------------------------------------------------------------------
    // Combat — per-strike hit flags reset on enterState
    // -------------------------------------------------------------------------
    private boolean hit1Landed, hit2Landed, hit3Landed;

    // Attack hitbox (separata dal corpo)
    private BaseActor attackHitbox;
    private boolean attackHitboxActive;

    // -------------------------------------------------------------------------
    // Player reference
    // -------------------------------------------------------------------------
    private Pablo pablo;

    // -------------------------------------------------------------------------
    // Animations
    // -------------------------------------------------------------------------
    private Animation animIdle;
    private Animation animWalk;
    private Animation animTurn;
    private Animation animShieldAnticipate;
    private Animation animShieldFrontImpact; // shield(front)1
    private Animation animShieldFrontHold;   // shield(front)2
    private Animation animShieldTop;         // shield(top)1+2
    private Animation animShieldTopImpact;   // shield(topBump)1
    private Animation animShieldTopHold;     // shield(topBump)2
    private Animation animWindupIntro;       // attack1-3
    private Animation animWindupHold;        // attack4 held
    private Animation animAttackStrikes;     // attack5-8
    private Animation animDeathAir;
    private Animation animDeathLand;
    private Animation animDeathCorpse;

    // Detection
    private static final float DETECTION_RADIUS      = 220f;

    public HuskWarrior(float x, float y, Stage stage, Pablo pablo)
    {
        super(x, y, stage);
        this.pablo = pablo;

        health = 16; // 4 unshielded hits from Pablo (4 dmg each)

        animIdle = loadAnimationFromFiles(new String[]{
                PATH+"idle1.png", PATH+"idle2.png", PATH+"idle3.png",
                PATH+"idle4.png", PATH+"idle5.png", PATH+"idle6.png"
        }, 0.083f, true);

        animWalk = loadAnimationFromFiles(new String[]{
                PATH+"walk1.png", PATH+"walk2.png", PATH+"walk3.png",
                PATH+"walk4.png", PATH+"walk5.png", PATH+"walk6.png",
                PATH+"walk7.png"
        }, 0.083f, true);

        animTurn = loadAnimationFromFiles(new String[]{
                PATH+"turn1.png", PATH+"turn2.png"
        }, 0.083f, false);

        // Shield anticipate: single frame, 40ms
        animShieldAnticipate = loadAnimationFromFiles(new String[]{
                PATH+"shield(anticipate).png"
        }, 0.040f, false);

        // Shield front: impact frame, then hold frame (separate anims for clean phasing)
        animShieldFrontImpact = loadAnimationFromFiles(new String[]{
                PATH+"shield(front)1.png"
        }, 0.050f, false);

        animShieldFrontHold = loadAnimationFromFiles(new String[]{
                PATH+"shield(front)2.png"
        }, 1f, true);

        // Shield top: raise sequence plays once
        animShieldTop = loadAnimationFromFiles(new String[]{
                PATH+"shield(top)1.png", PATH+"shield(top)2.png"
        }, 0.083f, false);

        animShieldTopImpact = loadAnimationFromFiles(new String[]{
                PATH+"shield(topBump)1.png"
        }, 0.050f, false);

        animShieldTopHold = loadAnimationFromFiles(new String[]{
                PATH+"shield(topBump)2.png"
        }, 1f, true);

        // Windup: attack1-3 intro, then attack4 held (same split as HuskHornhead anticipate)
        animWindupIntro = loadAnimationFromFiles(new String[]{
                PATH+"attack1.png", PATH+"attack2.png", PATH+"attack3.png"
        }, 0.066f, false);

        animWindupHold = loadAnimationFromFiles(new String[]{
                PATH+"attack4.png"
        }, 1f, true);

        // Three strikes: average frame duration (~52ms); hitboxes spawned by stateTimer
        animAttackStrikes = loadAnimationFromFiles(new String[]{
                PATH+"attack5.png", PATH+"attack6.png",
                PATH+"attack7.png", PATH+"attack8.png"
        }, 0.052f, false);

        animDeathAir = loadAnimationFromFiles(new String[]{
                PATH+"death(air).png"
        }, 1f, true);

        animDeathLand = loadAnimationFromFiles(new String[]{
                PATH+"death(land)1.png", PATH+"death(land)2.png",
                PATH+"death(land)3.png", PATH+"death(land)4.png",
                PATH+"death(land)5.png", PATH+"death(land)6.png",
                PATH+"death(land)7.png"
        }, 0.066f, false);

        animDeathCorpse = loadAnimationFromFiles(new String[]{
                PATH+"death(land)8.png"
        }, 1f, true);

        setBoundaryRectangle();

        attackHitbox = new BaseActor(0, 0, stage);
        attackHitbox.loadTexture("assets/white.png");
        attackHitbox.setSize(getWidth() * 0.55f, getHeight() * 0.35f);
        attackHitbox.setBoundaryRectangle();
        attackHitbox.setVisible(false);

        belowSensor = new BaseActor(0, 0, stage);
        belowSensor.loadTexture("assets/white.png");
        belowSensor.setSize(getWidth() - 8f, 6f);
        belowSensor.setBoundaryRectangle();
        belowSensor.setVisible(false);

        edgeSensor = new BaseActor(0, 0, stage);
        edgeSensor.loadTexture("assets/white.png");
        edgeSensor.setSize(6f, 6f);
        edgeSensor.setBoundaryRectangle();
        edgeSensor.setVisible(false);

        // Posiziona i sensori subito per il primo frame
        updateSensorPositions();

        enterState(HuskWarriorState.IDLE);
    }

    @Override
    public void act(float dt)
    {
        super.act(dt);

        if (!canUpdateAI() && !isInDeathSequence())
            return;

        if (state == HuskWarriorState.HIT_STOP)
        {
            hitStopTimer -= dt;
            if (hitStopTimer <= 0f)
                launchDeath();
            return;
        }

        stateTimer += dt;

        switch (state)
        {
            case IDLE:              tickIdle(dt);            break;
            case PATROL:            tickPatrol(dt);          break;
            case TURNING:           tickTurning(dt);         break;
            case SHIELD_ANTICIPATE: tickShieldAnticipate(dt);break;
            case SHIELD_FRONT:      tickShieldFront(dt);     break;
            case SHIELD_TOP:        tickShieldTop(dt);       break;
            case SHIELD_TOP_BUMP:   tickShieldTopBump(dt);   break;
            case ATTACK_WINDUP:     tickAttackWindup(dt);    break;
            case ATTACKING:         tickAttacking(dt);       break;
            case ATTACK_COOLDOWN:   tickAttackCooldown(dt);  break;
            case DEAD_AIR:          tickDeadAir(dt);         break;
            case DEAD_LAND:         tickDeadLand(dt);        break;
        }
    }

    private void tickIdle(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animIdle);
        faceDirection(direction);

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (stateTimer >= IDLE_DURATION)
            enterState(HuskWarriorState.PATROL);
    }

    private void tickPatrol(float dt)
    {
        applyGravity(dt);
        updateSensorPositions();

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (isOnGround() && !edgeAheadHasground())
        {
            enterState(HuskWarriorState.TURNING);
            return;
        }

        velocityVec.x = direction * PATROL_SPEED;
        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animWalk);
        syncFacingToHorizontalMovement();
    }

    private void tickTurning(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animTurn);

        if (isInDetectionRange())
        {
            faceTarget();
            enterState(HuskWarriorState.ATTACK_WINDUP);
            return;
        }

        if (animTurn.isAnimationFinished(stateTimer))
        {
            flip();
            enterState(HuskWarriorState.PATROL);
        }
    }

    private void tickShieldAnticipate(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animShieldAnticipate);
        faceDirection(direction);

        if (stateTimer >= SHIELD_ANTICIPATE_DUR)
            enterState(HuskWarriorState.SHIELD_FRONT);
    }

    private void tickShieldFront(float dt)
    {
        applyGravity(dt);
        updateSensorPositions();

        float total = SHIELD_FRONT_IMPACT + SHIELD_FRONT_HOLD;

        if (stateTimer < SHIELD_FRONT_IMPACT)
        {
            // Impact frame — planted
            setAnimation(animShieldFrontImpact);
            velocityVec.x = 0;
        }
        else
        {
            // Hold frame — recoil pushback away from Pablo
            setAnimation(animShieldFrontHold);
            float recoilDir;

            if (pablo.getX() > getX())
                recoilDir = -1f;
            else
                recoilDir = 1f;
            velocityVec.x   = recoilDir * RECOIL_SPEED;
        }

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        syncFacingToHorizontalMovement();

        if (stateTimer >= total)
            enterState(HuskWarriorState.ATTACK_WINDUP);
    }

    private void tickShieldTop(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animShieldTop);
        faceDirection(direction);

        if (stateTimer >= SHIELD_TOP_DUR)
            enterState(HuskWarriorState.SHIELD_TOP_BUMP);
    }

    private void tickShieldTopBump(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        float total = SHIELD_TOP_BUMP_IMPACT + SHIELD_TOP_BUMP_HOLD;

        if (stateTimer < SHIELD_TOP_BUMP_IMPACT)
            setAnimation(animShieldTopImpact);
        else
            setAnimation(animShieldTopHold);

        faceDirection(direction);

        if (stateTimer >= total)
            enterState(HuskWarriorState.PATROL);
    }

    private void tickAttackWindup(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        if (stateTimer < WINDUP_INTRO_DUR)
            setAnimation(animWindupIntro); // attack1-3 at 66ms each
        else
            setAnimation(animWindupHold);  // attack4 held for 150ms

        faceDirection(direction);

        if (stateTimer >= WINDUP_TOTAL_DUR)
            enterState(HuskWarriorState.ATTACKING);
    }

    private void tickAttacking(float dt)
    {
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animAttackStrikes);
        faceDirection(direction);

        boolean inStrike1 = stateTimer < STRIKE1_WINDOW;
        boolean inStrike2 = stateTimer >= STRIKE2_START && stateTimer < (STRIKE2_START + STRIKE2_WINDOW);
        boolean inStrike3 = stateTimer >= STRIKE3_START && stateTimer < (STRIKE3_START + STRIKE3_WINDOW);
        attackHitboxActive = inStrike1 || inStrike2 || inStrike3;
        syncAttackHitbox();

        // Strike 1 — attack5+6 window
        if (inStrike1 && !hit1Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit1Landed = true;
        }

        // Strike 2 — attack7 window
        if (inStrike2 && !hit2Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit2Landed = true;
        }

        // Strike 3 — attack8 window
        if (inStrike3 && !hit3Landed)
        {
            if (attackHitbox.overlaps(pablo)) pablo.takeDamage(1);
            hit3Landed = true;
        }

        if (stateTimer >= ATTACK_TOTAL_DUR)
            enterState(HuskWarriorState.ATTACK_COOLDOWN);
    }

    private void tickAttackCooldown(float dt)
    {
        // Punish window: warrior rests, shield is DOWN, all hits land
        applyGravity(dt);
        velocityVec.x = 0;
        moveBy(0, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animIdle);
        faceDirection(direction);

        if (stateTimer >= ATTACK_COOLDOWN_DUR)
            enterState(HuskWarriorState.IDLE);
    }

    private void tickDeadAir(float dt)
    {
        velocityVec.y -= DEATH_GRAVITY * dt;
        velocityVec.y  = Math.max(velocityVec.y, -MAX_FALL_SPEED);

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        updateSensorPositions();

        setAnimation(animDeathAir);
        setRotation(getRotation() + spinDir * SPIN_SPEED * dt);
        syncFacingToHorizontalMovement();

        if (isOnGround())
        {
            velocityVec.set(0, 0);
            setRotation(0); // snap on impact
            enterState(HuskWarriorState.DEAD_LAND);
        }
    }

    private void tickDeadLand(float dt)
    {
        if (stateTimer < LAND_TUMBLE_DURATION)
        {
            // Frames 1-7: tumble with decelerating slide
            float progress   = stateTimer / LAND_TUMBLE_DURATION;
            float slideSpeed = 60f * (1f - progress);
            velocityVec.x = deathKnockbackDir * slideSpeed;
            moveBy(velocityVec.x * dt, 0);
            syncFacingToHorizontalMovement();
            setAnimation(animDeathLand);
        }
        else
        {
            // Frame 8: hold forever — no remove()
            velocityVec.set(0, 0);
            setAnimation(animDeathCorpse);
        }
    }

    @Override
    public void takeDamage(int amount)
    {
        // Ignore during death
        if (state == HuskWarriorState.HIT_STOP ||
                state == HuskWarriorState.DEAD_AIR   ||
                state == HuskWarriorState.DEAD_LAND)
            return;

        // Ignore during active combat (committed to attack)
        if (state == HuskWarriorState.ATTACK_WINDUP ||
                state == HuskWarriorState.ATTACKING)
            return;

        // Already in a shield state — ignore repeat hits
        if (state == HuskWarriorState.SHIELD_ANTICIPATE ||
                state == HuskWarriorState.SHIELD_FRONT    ||
                state == HuskWarriorState.SHIELD_TOP      ||
                state == HuskWarriorState.SHIELD_TOP_BUMP)
            return;

        // Blocking only active while patrolling — cooldown is the punish window
        boolean canBlock = (state == HuskWarriorState.IDLE    ||
                state == HuskWarriorState.PATROL   ||
                state == HuskWarriorState.TURNING);

        if (canBlock && isPogoFromAbove())
        {
            pablo.velocityVec.y = POGO_BOUNCE_SPEED; // bounce Pablo upward
            enterState(HuskWarriorState.SHIELD_TOP);
            return; // no damage
        }

        if (canBlock && isShieldFacingPablo())
        {
            enterState(HuskWarriorState.SHIELD_ANTICIPATE); // block → retaliate
            return; // no damage
        }

        // Unshielded hit (from behind, or during cooldown)
        health -= amount;

        if (health <= 0)
        {
            health = 0;
            if (pablo.getX() < getX())
                deathKnockbackDir = 1f;
            else
                deathKnockbackDir = -1f;
            spinDir           = deathKnockbackDir;
            hitStopTimer      = HIT_STOP_DURATION;
            spawnShieldProp();
            enterState(HuskWarriorState.HIT_STOP);
        }
    }

    private void launchDeath()
    {
        velocityVec.x = deathKnockbackDir * DEATH_KNOCKBACK_X;
        velocityVec.y = DEATH_KNOCKBACK_Y;
        enterState(HuskWarriorState.DEAD_AIR);
    }

    @Override
    public void onWallHit()
    {
        if (state == HuskWarriorState.PATROL)
            flip();
        // All other states: walls are ignored
    }

    private void spawnShieldProp()
    {
        // Shield flies opposite to knockback direction and arcs upward
        float shieldVelX = -deathKnockbackDir * 190f;
        float shieldVelY = 310f;
        float shieldSpin = deathKnockbackDir * 380f; // degrees/sec
        new ShieldProp(getX(), getY() + getHeight() * 0.5f,
                getStage(), shieldVelX, shieldVelY, shieldSpin);
    }

    // Returns true if the shield side of the warrior is the side Pablo is on
    private boolean isShieldFacingPablo()
    {
        float pabloCenterX = pablo.getX() + pablo.getWidth()  / 2f;
        float selfCenterX  = getX()       + getWidth()        / 2f;
        if (direction > 0)
            return pabloCenterX > selfCenterX;
        else
            return pabloCenterX < selfCenterX;
    }

    private boolean isInDetectionRange()
    {
        float selfX = getX() + getWidth() / 2f;
        float selfY = getY() + getHeight() / 2f;

        float pabloX = pablo.getX() + pablo.getWidth() / 2f;
        float pabloY = pablo.getY() + pablo.getHeight() / 2f;

        float dx = pabloX - selfX;
        float dy = pabloY - selfY;

        return dx * dx + dy * dy < DETECTION_RADIUS * DETECTION_RADIUS;
    }

    private void faceTarget()
    {
        if (pablo.getX() > getX())
            direction = 1f;
        else
            direction = -1f;
        faceDirection(direction);
    }

    // True when Pablo is falling from above the warrior's midpoint
    private boolean isPogoFromAbove()
    {
        float warriorMidY  = getY() + getHeight() * 0.5f;
        float pabloCenterY = pablo.getY() + pablo.getHeight() / 2f;
        return pabloCenterY > warriorMidY && pablo.velocityVec.y < 0;
    }

    private void enterState(HuskWarriorState next)
    {
        state       = next;
        stateTimer  = 0f;
        elapsedTime = 0f;
        hit1Landed  = false;
        hit2Landed  = false;
        hit3Landed  = false;
        if (next != HuskWarriorState.ATTACKING)
        {
            attackHitboxActive = false;
            attackHitbox.setVisible(false);
        }
    }

    private boolean isInDeathSequence()
    {
        return state == HuskWarriorState.HIT_STOP ||
                state == HuskWarriorState.DEAD_AIR ||
                state == HuskWarriorState.DEAD_LAND;
    }

    private void syncAttackHitbox()
    {
        if (!attackHitboxActive)
        {
            attackHitbox.setVisible(false);
            return;
        }

        float hx;
        if (direction > 0)
            hx = getX() + getWidth();
        else
            hx = getX() - attackHitbox.getWidth();

        float hy = getY() + getHeight() * 0.30f;

        attackHitbox.setPosition(hx, hy);
        attackHitbox.setVisible(true);
    }

    // =========================================================================
    // Shield Prop — independent physics actor spawned at moment of death
    // =========================================================================
    private static class ShieldProp extends BaseActor
    {
        private float velX, velY;
        private float spinRate;
        private static final float GRAVITY = 1000f;

        ShieldProp(float x, float y, Stage stage, float velX, float velY, float spinRate)
        {
            super(x, y, stage);
            this.velX     = velX;
            this.velY     = velY;
            this.spinRate = spinRate;
            loadTexture("assets/HuskWarrior/death(shield).png");
            setBoundaryRectangle();
        }

        @Override
        public void act(float dt)
        {
            super.act(dt);
            velY -= GRAVITY * dt;
            moveBy(velX * dt, velY * dt);
            setRotation(getRotation() + spinRate * dt);
            if (getY() < -200f) remove(); // self-cleanup when off-screen
        }
    }
}

// LevelScreen.java

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.Pixmap;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.BitmapFont;
import com.badlogic.gdx.graphics.g2d.TextureRegion;
import com.badlogic.gdx.maps.MapObject;
import com.badlogic.gdx.maps.MapProperties;
import com.badlogic.gdx.maps.objects.RectangleMapObject;
import com.badlogic.gdx.maps.objects.PolygonMapObject;
import com.badlogic.gdx.math.EarClippingTriangulator;
import com.badlogic.gdx.math.Polygon;
import com.badlogic.gdx.math.Rectangle;
import com.badlogic.gdx.math.Vector2;
import com.badlogic.gdx.utils.ShortArray;

import com.badlogic.gdx.scenes.scene2d.Actor;
import com.badlogic.gdx.scenes.scene2d.ui.Image;
import com.badlogic.gdx.scenes.scene2d.ui.Label;
import com.badlogic.gdx.scenes.scene2d.ui.Label.LabelStyle;
import com.badlogic.gdx.scenes.scene2d.ui.Table;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton.TextButtonStyle;
import com.badlogic.gdx.scenes.scene2d.utils.ChangeListener;
import com.badlogic.gdx.scenes.scene2d.utils.TextureRegionDrawable;
import pablo.entities.enemies.crawlid.Crawlid;
import pablo.entities.enemies.Enemy;
import pablo.entities.enemies.falseKnight.FalseKnight;
import pablo.entities.enemies.tiktik.Tiktik;
import pablo.entities.enemies.vengefly.Vengefly;
import pablo.entities.player.Pablo;
import pablo.framework.BaseActor;
import pablo.framework.BaseGame;
import pablo.framework.BaseScreen;
import pablo.framework.TilemapActor;

import com.badlogic.gdx.graphics.Camera;

import pablo.entities.enemies.huskBully.HuskBully;
import pablo.entities.enemies.huskHornhead.HuskHornhead;
import pablo.entities.enemies.huskWarrior.HuskWarrior;

import java.util.ArrayList;

public class LevelScreen extends BaseScreen
{
    // -----------------------------------------------------------------------
    // Path mappa — parametrico: passa il .tmx che vuoi nel costruttore
    // -----------------------------------------------------------------------
    private static final String DEFAULT_MAP = "assets/Maps/Mappa1.tmx";
    private final String mapPath;
    private final String spawnSide; // "start", "left", "right"

    // -----------------------------------------------------------------------
    // Asset paths
    // -----------------------------------------------------------------------
    private static final String MASK_PATH = "assets/mask.png";
    private static final String SOUL_DIR  = "assets/soul/";

    // Colori maschere
    private static final Color MASK_FULL  = Color.WHITE;
    private static final Color MASK_EMPTY = new Color(0.15f, 0.15f, 0.15f, 0.85f);

    // -----------------------------------------------------------------------
    // Ricettacolo anima
    // -----------------------------------------------------------------------
    private static final int   VESSEL_STATES    = 9;
    private static final int   FRAMES_PER_STATE = 6;
    private static final float FRAME_DURATION   = 0.083f;

    private TextureRegionDrawable[][] vesselDrawables;
    private Texture[][]               vesselTextures;

    private Image vesselImage;
    private float vesselAnimTime  = 0f;
    private int   lastVesselState = -1;

    // -----------------------------------------------------------------------
    // Campi
    // -----------------------------------------------------------------------
    private Pablo pablo;

    private Texture  maskTexture;
    private Image[]  maskImages;

    // FalseKnight è opzionale: null se la mappa non lo contiene
    private FalseKnight falseKnight = null;

    private BaseActor bossTrigger = null;
    private Vector2 bossTeleportPoint = null;
    private Vector2 bossSpawnPoint = null;
    private boolean bossDialogOpen = false;
    private boolean bossFightStarted = false;

    private Table bossDialog;
    private Texture dialogTexture;
    private BitmapFont dialogFont;
    private Texture dialogBtnUpTexture;
    private Texture dialogBtnDownTexture;

    private float shakeDuration  = 0f;
    private float shakeIntensity = 5f;
    private float enemyRuntimeLogTimer = 0f;
    private int   enemyRuntimeLogCount = 0;

    // -----------------------------------------------------------------------
    // UI scaling HUD
    // -----------------------------------------------------------------------
    private static final float HUD_SCALE       = 1.75f;
    private static final float MASK_W          = 40f * HUD_SCALE;
    private static final float MASK_H          = 32f * HUD_SCALE;
    private static final float MASK_PAD_RIGHT  = 6f  * HUD_SCALE;
    private static final float VESSEL_SIZE     = 48f * HUD_SCALE;
    private static final float HUD_PAD_TOP     = 14f * HUD_SCALE;
    private static final float VESSEL_PAD_TOP  = 10f * HUD_SCALE;
    private static final float VESSEL_PAD_LEFT = 20f * HUD_SCALE;

    private float voidTimer = 0f;
    private static final float VOID_RESPAWN_DELAY = 0.2f;

    // -----------------------------------------------------------------------
    // Costruttori
    // -----------------------------------------------------------------------

    /** Usa la mappa di default. */
    public LevelScreen()
    {
        this(DEFAULT_MAP, "start");
    }

    /** Usa la mappa specificata. */
    public LevelScreen(String mapPath)
    {
        this(mapPath, "start");
    }

    /** Usa la mappa e lato di spawn specificati. */
    public LevelScreen(String mapPath, String spawnSide)
    {
        super();
        this.mapPath = mapPath;
        this.spawnSide = (spawnSide != null) ? spawnSide : "start";
        initializeLevel();
    }

    // -----------------------------------------------------------------------
    // initialize()
    // -----------------------------------------------------------------------
    public void initialize()
    {
        // BaseScreen chiama initialize() nel suo costruttore: qui evitiamo
        // di usare campi non ancora assegnati e inizializziamo dopo.
    }

    private void initializeLevel()
    {
        // Se mapPath è null, usa la mappa di default
        String effectiveMapPath = (mapPath != null) ? mapPath : DEFAULT_MAP;
        if (mapPath == null)
            Gdx.app.log("LevelScreen", "mapPath è null, usando default: " + DEFAULT_MAP);

        Gdx.app.log("LevelScreen", "Caricamento mappa: " + effectiveMapPath);

        TilemapActor tma = new TilemapActor(effectiveMapPath, mainStage);

        // Solidi
        for (MapObject obj : tma.getRectangleList("solido"))
        {
            if (obj instanceof RectangleMapObject)
            {
                Rectangle rect = ((RectangleMapObject) obj).getRectangle();
                new Object(rect.x, rect.y, rect.width, rect.height, mainStage);
                continue;
            }

            if (obj instanceof PolygonMapObject)
            {
                addSolidTriangles(((PolygonMapObject) obj).getPolygon());
            }
        }

        // Punto di spawn — errore chiaro se mancante
        ArrayList<MapObject> startPoints = tma.getRectangleList("start");
        if (startPoints.isEmpty())
            throw new IllegalStateException(
                    "[LevelScreen] Nessun oggetto 'start' trovato in: " + mapPath
                            + "\nControlla che il layer Oggetti abbia un rettangolo con nome 'start'.");

        MapObject startPoint = startPoints.get(0);
        MapProperties startProps = startPoint.getProperties();
        pablo = new Pablo(
                (float) startProps.get("x"),
                (float) startProps.get("y"),
                mainStage
        );
        PlayerState.applyTo(pablo);
        if (spawnSide.equals("right")) {
            // Viene dalla mappa a destra → lo metti al bordo destro
            pablo.setX(BaseActor.getWorldBounds().width - pablo.getWidth() - 10f);
        } else if (spawnSide.equals("left")) {
            // Viene dalla mappa a sinistra → lo metti al bordo sinistro
            pablo.setX(10f);
        }
        pablo.setSoul(0);


        // -----------------------------------------------------------------------
        // UI — maschere HP
        // -----------------------------------------------------------------------
        maskTexture = loadTextureSafe(MASK_PATH, Color.WHITE);
        maskImages  = new Image[pablo.getMaxHealth()];

        Table maskRow = new Table();
        for (int i = 0; i < pablo.getMaxHealth(); i++)
        {
            maskImages[i] = new Image(maskTexture);
            maskImages[i].setColor(MASK_FULL);
            maskRow.add(maskImages[i]).size(MASK_W, MASK_H).padRight(MASK_PAD_RIGHT);
        }

        // -----------------------------------------------------------------------
        // UI — ricettacolo anima
        // -----------------------------------------------------------------------
        vesselTextures  = new Texture[VESSEL_STATES][];
        vesselDrawables = new TextureRegionDrawable[VESSEL_STATES][];

        vesselTextures[0]  = new Texture[1];
        vesselDrawables[0] = new TextureRegionDrawable[1];
        vesselTextures[0][0]  = createEmptyVesselTexture((int) VESSEL_SIZE);
        vesselDrawables[0][0] = new TextureRegionDrawable(
                new TextureRegion(vesselTextures[0][0]));

        for (int state = 1; state < VESSEL_STATES; state++)
        {
            vesselTextures[state]  = new Texture[FRAMES_PER_STATE];
            vesselDrawables[state] = new TextureRegionDrawable[FRAMES_PER_STATE];

            for (int frame = 0; frame < FRAMES_PER_STATE; frame++)
            {
                String path = SOUL_DIR + state + "_" + (frame + 1) + ".png";
                Color fb = new Color(state / 8f, state / 8f, state / 8f, 1f);
                vesselTextures[state][frame]  = loadTextureSafe(path, fb);
                vesselDrawables[state][frame] = new TextureRegionDrawable(
                        new TextureRegion(vesselTextures[state][frame]));
            }
        }

        vesselImage = new Image(vesselDrawables[0][0]);

        // Layout UI
        uiTable.top().left();
        uiTable.add(maskRow).left().padTop(HUD_PAD_TOP).padLeft(14).row();
        uiTable.add(vesselImage).size(VESSEL_SIZE, VESSEL_SIZE)
                .left().padTop(VESSEL_PAD_TOP).padLeft(VESSEL_PAD_LEFT).row();

        // -----------------------------------------------------------------------
        // Nemici comuni
        // -----------------------------------------------------------------------
        spawnEnemiesFromMap(tma);

        // -----------------------------------------------------------------------
        // Trigger boss e spawn point
        // -----------------------------------------------------------------------
        setupBossTrigger(tma);

        // -----------------------------------------------------------------------
        // FalseKnight — opzionale
        // -----------------------------------------------------------------------
        if (bossTrigger == null)
        {
            spawnFalseKnightIfPresent();
        }
        else
        {
            Gdx.app.log("LevelScreen", "FalseKnight in attesa di conferma dialogo.");
        }

        // Z-order
        tma.toBack();
        for (BaseActor eActor : BaseActor.getList(mainStage, Enemy.class.getName()))
            eActor.toFront();
        if (falseKnight != null) falseKnight.toFront();
        pablo.toFront();
    }

    // -----------------------------------------------------------------------
    // spawnEnemiesFromMap()
    // -----------------------------------------------------------------------
    private void spawnEnemiesFromMap(TilemapActor tma)
    {
        spawnEnemyType(tma, "Crawlid");
        spawnEnemyType(tma, "Tiktik");
        spawnEnemyType(tma, "Vengefly");
        spawnEnemyType(tma, "HuskBully");
        spawnEnemyType(tma, "HuskHornhead");
        spawnEnemyType(tma, "HuskWarrior");
    }

    private void spawnEnemyType(TilemapActor tma, String type)
    {
        ArrayList<MapObject> objects = tma.getRectangleList(type);

        for (MapObject obj : objects)
        {
            MapProperties props = obj.getProperties();
            float x = (float) props.get("x");
            float y = (float) props.get("y");

            Enemy enemy = createEnemy(type, x, y);
            enemy.toFront();
        }
    }

    private Enemy createEnemy(String type, float x, float y)
    {
        switch (type)
        {
            case "Crawlid":      return new Crawlid(x, y, mainStage, pablo);
            case "Tiktik":       return new Tiktik(x, y, mainStage, pablo);
            case "Vengefly":     return new Vengefly(x, y, mainStage, pablo);
            case "HuskBully":    return new HuskBully(x, y, mainStage, pablo);
            case "HuskHornhead": return new HuskHornhead(x, y, mainStage, pablo);
            case "HuskWarrior":  return new HuskWarrior(x, y, mainStage, pablo);
            default: throw new IllegalArgumentException("Tipo nemico sconosciuto: " + type);
        }
    }

    // -----------------------------------------------------------------------
    // update()
    // -----------------------------------------------------------------------
    public void update(float dt)
    {
        SoundManager.get().update(dt);

        // Maschere HP
        int health = pablo.getHealth();
        for (int i = 0; i < maskImages.length; i++)
            maskImages[i].setColor(i < health ? MASK_FULL : MASK_EMPTY);

        // Ricettacolo anima
        updateVessel(dt);

        // Void fall
        if (pablo.getY() <= 2f && !pablo.isOnSolid())
        {
            voidTimer += dt;
            if (voidTimer >= VOID_RESPAWN_DELAY)
            {
                pablo.respawn();
                voidTimer = 0f;
            }
            return;
        }
        else
        {
            voidTimer = 0f;
        }

        // Collisioni player <-> solidi
        for (BaseActor actor : BaseActor.getList(mainStage, Object.class.getName()))
        {
            Object oggetto = (Object) actor;
            if (pablo.overlaps(oggetto) && oggetto.isEnable())
            {
                Vector2 offset = pablo.preventOverlap(oggetto);
                if (offset != null)
                {
                    if (Math.abs(offset.x) > Math.abs(offset.y))
                        pablo.velocityVec.x = 0;
                    else
                        pablo.velocityVec.y = 0;
                }
            }
        }

        // Collisioni nemici <-> solidi
        for (BaseActor eActor : BaseActor.getList(mainStage, Enemy.class.getName()))
        {
            Enemy enemy = (Enemy) eActor;
            for (BaseActor sActor : BaseActor.getList(mainStage, Object.class.getName()))
            {
                Object solid = (Object) sActor;
                if (enemy.overlaps(solid) && solid.isEnable())
                {
                    Vector2 offset = enemy.preventOverlap(solid);
                    if (offset != null)
                    {
                        if (Math.abs(offset.x) > Math.abs(offset.y))
                        {
                            enemy.velocityVec.x = 0;
                            enemy.onWallHit();
                        }
                        else
                        {
                            enemy.velocityVec.y = 0;
                        }
                    }
                }
            }
        }

        // Screen shake
        if (shakeDuration > 0)
        {
            shakeDuration -= dt;
            Camera cam = mainStage.getCamera();
            cam.position.y += (Math.random() > 0.5 ? 1 : -1) * shakeIntensity;
            cam.update();
        }

        // Trigger dialogo boss
        if (bossTrigger != null && !bossFightStarted && !bossDialogOpen)
        {
            if (pablo.overlaps(bossTrigger) && Gdx.input.isKeyJustPressed(Input.Keys.E))
                openBossDialog();
        }

        // FalseKnight — solo se presente nella mappa
        if (falseKnight != null && !falseKnight.isDead())
        {
            for (BaseActor sActor : BaseActor.getList(mainStage, Object.class.getName()))
            {
                Object solid = (Object) sActor;
                if (falseKnight.overlaps(solid) && solid.isEnable())
                {
                    Vector2 offset = falseKnight.preventOverlap(solid);
                    if (offset != null)
                    {
                        if (Math.abs(offset.x) > Math.abs(offset.y))
                        {
                            falseKnight.velocityVec.x = 0;
                            falseKnight.onWallHit();
                        }
                        else
                        {
                            falseKnight.velocityVec.y = 0;
                            falseKnight.onGroundLanded();
                        }
                    }
                }
            }

            if (falseKnight.maceOverlapsPablo())
                pablo.takeDamage(1);
        }

        // Transizione mappa destra
        MapGraph.MapNode node = MapGraph.get(mapPath);
        if (node != null && node.rightNeighbor != null) {
            if (pablo.getX() + pablo.getWidth() >= BaseActor.getWorldBounds().width - 2f) {
                PlayerState.saveFrom(pablo);
                BaseGame.setActiveScreen(new LevelScreen(node.rightNeighbor, "left"));
            }
        }
        // Transizione mappa sinistra
        if (node != null && node.leftNeighbor != null) {
            if (pablo.getX() <= 2f) {
                PlayerState.saveFrom(pablo);
                BaseGame.setActiveScreen(new LevelScreen(node.leftNeighbor, "right"));
            }
        }

        logEnemyRuntimeState(dt);
    }

    private void logEnemyRuntimeState(float dt)
    {
        if (enemyRuntimeLogCount >= 5) return;
        enemyRuntimeLogTimer += dt;
        if (enemyRuntimeLogTimer < 1f) return;

        enemyRuntimeLogTimer = 0f;
        enemyRuntimeLogCount++;

        Camera cam = mainStage.getCamera();
        Gdx.app.log("EnemyRuntime", "sample=" + enemyRuntimeLogCount
                + " camera=" + cam.position.x + "," + cam.position.y
                + " enemies=" + BaseActor.count(mainStage, Enemy.class.getName()));
    }

    // -----------------------------------------------------------------------
    // updateVessel()
    // -----------------------------------------------------------------------
    private void updateVessel(float dt)
    {
        int soul = pablo.getSoul();
        int vesselState = getVesselStateForSoul(soul);

        if (vesselState != lastVesselState)
        {
            vesselAnimTime  = 0f;
            lastVesselState = vesselState;
        }

        if (vesselState == 0)
        {
            vesselImage.setDrawable(vesselDrawables[0][0]);
            return;
        }

        vesselAnimTime += dt;
        int   frameCount     = vesselDrawables[vesselState].length;
        float totalDuration  = FRAME_DURATION * frameCount;
        vesselAnimTime %= totalDuration;

        int frameIndex = (int)(vesselAnimTime / FRAME_DURATION);
        frameIndex = Math.min(frameIndex, frameCount - 1);

        vesselImage.setDrawable(vesselDrawables[vesselState][frameIndex]);
    }

    // -----------------------------------------------------------------------
    // keyDown()
    // -----------------------------------------------------------------------
    public boolean keyDown(int keyCode)
    {
        if (bossDialogOpen)
        {
            if (keyCode == Input.Keys.ENTER)
            {
                closeBossDialog();
                if (bossTeleportPoint != null)
                {
                    pablo.setPosition(bossTeleportPoint.x, bossTeleportPoint.y);
                    pablo.velocityVec.set(0, 0);
                }
                spawnFalseKnightIfPresent();
                return true;
            }
            if (keyCode == Input.Keys.ESCAPE)
            {
                closeBossDialog();
                return true;
            }
        }

        if (keyCode == Input.Keys.ESCAPE || keyCode == Input.Keys.P)
        {
            BaseGame.setActiveScreen(new PauseScreen(this));
            return true;
        }
        if (keyCode == Input.Keys.K) { pablo.takeDamage(1); return true; }
        if (keyCode == Input.Keys.O)
        {
            if (falseKnight != null) falseKnight.takeDamage(1);
            return true;
        }
        if (keyCode == Input.Keys.L) { bumpSoulToNextVesselState(); return true; }

        if (keyCode == Input.Keys.SPACE || keyCode == Input.Keys.W)
            if (pablo.isOnSolid()) pablo.jump();

        return false;
    }

    // -----------------------------------------------------------------------
    // Boss dialog / trigger
    // -----------------------------------------------------------------------
    private void setupBossTrigger(TilemapActor tma)
    {
        ArrayList<MapObject> tpObjects = tma.getRectangleList("tp");
        if (!tpObjects.isEmpty())
        {
            MapObject tpObj = tpObjects.get(0);
            if (tpObj instanceof RectangleMapObject)
            {
                Rectangle rect = ((RectangleMapObject) tpObj).getRectangle();
                bossTrigger = new BaseActor(rect.x, rect.y, mainStage);
                bossTrigger.setSize(rect.width, rect.height);
                bossTrigger.setBoundaryRectangle();
                bossTrigger.setVisible(false);
            }
        }

        ArrayList<MapObject> spawnTpObjects = tma.getRectangleList("spawntp");
        if (!spawnTpObjects.isEmpty())
        {
            MapObject sp = spawnTpObjects.get(0);
            MapProperties props = sp.getProperties();
            bossTeleportPoint = new Vector2((float) props.get("x"), (float) props.get("y"));
        }

        ArrayList<MapObject> falseKnightPoints = tma.getRectangleList("FalseKnight");
        if (!falseKnightPoints.isEmpty())
        {
            MapObject fkPoint = falseKnightPoints.get(0);
            MapProperties fkProps = fkPoint.getProperties();
            bossSpawnPoint = new Vector2((float) fkProps.get("x"), (float) fkProps.get("y"));
        }
    }

    private void spawnFalseKnightIfPresent()
    {
        if (bossSpawnPoint == null)
        {
            Gdx.app.log("LevelScreen", "FalseKnight non presente in questa mappa — skip.");
            return;
        }

        if (falseKnight != null) return;
        falseKnight = new FalseKnight(bossSpawnPoint.x, bossSpawnPoint.y, mainStage, pablo);
        falseKnight.setScreenShakeCallback(() -> shakeDuration = 0.15f);
        falseKnight.toFront();
        bossFightStarted = true;
        Gdx.app.log("LevelScreen", "FalseKnight spawned at " + bossSpawnPoint.x + "," + bossSpawnPoint.y);
    }

    private void openBossDialog()
    {
        if (bossDialog == null) buildBossDialog();
        bossDialog.setVisible(true);
        bossDialogOpen = true;
    }

    private void closeBossDialog()
    {
        if (bossDialog != null) bossDialog.setVisible(false);
        bossDialogOpen = false;
    }

    private void buildBossDialog()
    {
        dialogTexture = loadTextureSafe("assets/dialog.png", new Color(0f, 0f, 0f, 0.75f));
        dialogFont = new BitmapFont();
        dialogFont.getData().setScale(1.1f);

        Pixmap upPix = new Pixmap(1, 1, Pixmap.Format.RGBA8888);
        upPix.setColor(new Color(0.25f, 0.25f, 0.25f, 0.9f));
        upPix.fill();
        dialogBtnUpTexture = new Texture(upPix);
        upPix.dispose();

        Pixmap downPix = new Pixmap(1, 1, Pixmap.Format.RGBA8888);
        downPix.setColor(new Color(0.4f, 0.4f, 0.4f, 0.95f));
        downPix.fill();
        dialogBtnDownTexture = new Texture(downPix);
        downPix.dispose();

        TextButtonStyle btnStyle = new TextButtonStyle();
        btnStyle.font = dialogFont;
        btnStyle.up = new TextureRegionDrawable(new TextureRegion(dialogBtnUpTexture));
        btnStyle.down = new TextureRegionDrawable(new TextureRegion(dialogBtnDownTexture));
        btnStyle.over = btnStyle.down;

        LabelStyle labelStyle = new LabelStyle(dialogFont, Color.WHITE);

        Label message = new Label(
                "Questa è la tua prova finale, vuoi affrontare il boss?",
                labelStyle);
        message.setWrap(true);
        message.setAlignment(1);

        TextButton yesBtn = new TextButton("SI", btnStyle);
        TextButton noBtn  = new TextButton("NO", btnStyle);

        yesBtn.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor)
            {
                closeBossDialog();
                if (bossTeleportPoint != null)
                {
                    pablo.setPosition(bossTeleportPoint.x, bossTeleportPoint.y);
                    pablo.velocityVec.set(0, 0);
                }
                spawnFalseKnightIfPresent();
            }
        });

        noBtn.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor)
            {
                closeBossDialog();
            }
        });

        Table box = new Table();
        box.setBackground(new TextureRegionDrawable(new TextureRegion(dialogTexture)));
        box.pad(24f);
        box.add(message).width(520).center().row();

        Table buttons = new Table();
        buttons.add(yesBtn).width(120).height(36).padRight(20);
        buttons.add(noBtn).width(120).height(36);
        box.add(buttons).padTop(16).center();

        bossDialog = new Table();
        bossDialog.setFillParent(true);
        bossDialog.center();
        bossDialog.add(box).center();
        bossDialog.setVisible(false);
        uiStage.addActor(bossDialog);
    }

    // -----------------------------------------------------------------------
    // dispose()
    // -----------------------------------------------------------------------
    @Override
    public void dispose()
    {
        super.dispose();
        if (maskTexture != null) maskTexture.dispose();
        if (vesselTextures != null)
            for (Texture[] row : vesselTextures)
                if (row != null)
                    for (Texture t : row)
                        if (t != null) t.dispose();
        if (dialogTexture != null) dialogTexture.dispose();
        if (dialogFont != null) dialogFont.dispose();
        if (dialogBtnUpTexture != null) dialogBtnUpTexture.dispose();
        if (dialogBtnDownTexture != null) dialogBtnDownTexture.dispose();
    }

    private void addSolidTriangles(Polygon polygon)
    {
        float[] vertices = polygon.getVertices();
        if (vertices == null || vertices.length < 6) return;

        EarClippingTriangulator triangulator = new EarClippingTriangulator();
        ShortArray indices = triangulator.computeTriangles(vertices);
        Rectangle bounds = polygon.getBoundingRectangle();

        for (int i = 0; i < indices.size; i += 3)
        {
            int i1 = indices.get(i) * 2;
            int i2 = indices.get(i + 1) * 2;
            int i3 = indices.get(i + 2) * 2;

            float[] tri = new float[] {
                    vertices[i1], vertices[i1 + 1],
                    vertices[i2], vertices[i2 + 1],
                    vertices[i3], vertices[i3 + 1]
            };

            Object solid = new Object(polygon.getX(), polygon.getY(), bounds.width, bounds.height, mainStage);
            solid.setBoundaryPolygon(tri);
        }
    }
}

// LevelScreen.java

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.Pixmap;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.BitmapFont;
import com.badlogic.gdx.graphics.g2d.TextureRegion;
import com.badlogic.gdx.maps.MapObject;
import com.badlogic.gdx.maps.MapProperties;
import com.badlogic.gdx.maps.objects.RectangleMapObject;
import com.badlogic.gdx.maps.objects.PolygonMapObject;
import com.badlogic.gdx.math.EarClippingTriangulator;
import com.badlogic.gdx.math.Polygon;
import com.badlogic.gdx.math.Rectangle;
import com.badlogic.gdx.math.Vector2;
import com.badlogic.gdx.utils.ShortArray;
import com.badlogic.gdx.utils.Align;

import com.badlogic.gdx.scenes.scene2d.Actor;
import com.badlogic.gdx.scenes.scene2d.ui.Image;
import com.badlogic.gdx.scenes.scene2d.ui.Label;
import com.badlogic.gdx.scenes.scene2d.ui.Label.LabelStyle;
import com.badlogic.gdx.scenes.scene2d.ui.Table;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton.TextButtonStyle;
import com.badlogic.gdx.scenes.scene2d.utils.ChangeListener;
import com.badlogic.gdx.scenes.scene2d.utils.TextureRegionDrawable;
import pablo.entities.enemies.crawlid.Crawlid;
import pablo.entities.enemies.Enemy;
import pablo.entities.enemies.falseKnight.FalseKnight;
import pablo.entities.enemies.tiktik.Tiktik;
import pablo.entities.enemies.vengefly.Vengefly;
import pablo.entities.player.Pablo;
import pablo.framework.BaseActor;
import pablo.framework.BaseGame;
import pablo.framework.BaseScreen;
import pablo.framework.TilemapActor;

import com.badlogic.gdx.graphics.Camera;

import pablo.entities.enemies.huskBully.HuskBully;
import pablo.entities.enemies.huskHornhead.HuskHornhead;
import pablo.entities.enemies.huskWarrior.HuskWarrior;

import java.util.ArrayList;

public class LevelScreen extends BaseScreen
{
    // -----------------------------------------------------------------------
    // Path mappa — parametrico: passa il .tmx che vuoi nel costruttore
    // -----------------------------------------------------------------------
    private static final String DEFAULT_MAP = "assets/Maps/Mappa1.tmx";
    private final String mapPath;
    private final String spawnSide; // "start", "left", "right"

    // -----------------------------------------------------------------------
    // Asset paths
    // -----------------------------------------------------------------------
    private static final String MASK_PATH = "assets/mask.png";
    private static final String SOUL_DIR  = "assets/soul/";

    // Colori maschere
    private static final Color MASK_FULL  = Color.WHITE;
    private static final Color MASK_EMPTY = new Color(0.15f, 0.15f, 0.15f, 0.85f);

    // -----------------------------------------------------------------------
    // Ricettacolo anima
    // -----------------------------------------------------------------------
    private static final int   VESSEL_STATES    = 9;
    private static final int   FRAMES_PER_STATE = 6;
    private static final float FRAME_DURATION   = 0.083f;

    private TextureRegionDrawable[][] vesselDrawables;
    private Texture[][]               vesselTextures;

    private Image vesselImage;
    private float vesselAnimTime  = 0f;
    private int   lastVesselState = -1;

    // -----------------------------------------------------------------------
    // Campi
    // -----------------------------------------------------------------------
    private Pablo pablo;

    private Texture  maskTexture;
    private Image[]  maskImages;

    // FalseKnight è opzionale: null se la mappa non lo contiene
    private FalseKnight falseKnight = null;

    private BaseActor bossTrigger = null;
    private Vector2 bossTeleportPoint = null;
    private Vector2 bossSpawnPoint = null;
    private boolean bossDialogOpen = false;
    private boolean bossFightStarted = false;

    private Table bossDialog;
    private Texture dialogTexture;
    private BitmapFont dialogFont;
    private Texture dialogBtnUpTexture;
    private Texture dialogBtnDownTexture;

    private float shakeDuration  = 0f;
    private float shakeIntensity = 5f;
    private float enemyRuntimeLogTimer = 0f;
    private int   enemyRuntimeLogCount = 0;

    // -----------------------------------------------------------------------
    // UI scaling HUD
    // -----------------------------------------------------------------------
    private static final float HUD_SCALE       = 1.75f;
    private static final float MASK_W          = 40f * HUD_SCALE;
    private static final float MASK_H          = 32f * HUD_SCALE;
    private static final float MASK_PAD_RIGHT  = 6f  * HUD_SCALE;
    private static final float VESSEL_SIZE     = 48f * HUD_SCALE;
    private static final float HUD_PAD_TOP     = 14f * HUD_SCALE;
    private static final float VESSEL_PAD_TOP  = 10f * HUD_SCALE;
    private static final float VESSEL_PAD_LEFT = 20f * HUD_SCALE;

    private float voidTimer = 0f;
    private static final float VOID_RESPAWN_DELAY = 0.2f;

    // -----------------------------------------------------------------------
    // Costruttori
    // -----------------------------------------------------------------------

    /** Usa la mappa di default. */
    public LevelScreen()
    {
        this(DEFAULT_MAP, "start");
    }

    /** Usa la mappa specificata. */
    public LevelScreen(String mapPath)
    {
        this(mapPath, "start");
    }

    /** Usa la mappa e lato di spawn specificati. */
    public LevelScreen(String mapPath, String spawnSide)
    {
        super();
        this.mapPath = mapPath;
        this.spawnSide = (spawnSide != null) ? spawnSide : "start";
        initializeLevel();
    }

    // -----------------------------------------------------------------------
    // initialize()
    // -----------------------------------------------------------------------
    public void initialize()
    {
        // BaseScreen chiama initialize() nel suo costruttore: qui evitiamo
        // di usare campi non ancora assegnati e inizializziamo dopo.
    }

    private void initializeLevel()
    {
        // Se mapPath è null, usa la mappa di default
        String effectiveMapPath = (mapPath != null) ? mapPath : DEFAULT_MAP;
        if (mapPath == null)
            Gdx.app.log("LevelScreen", "mapPath è null, usando default: " + DEFAULT_MAP);

        Gdx.app.log("LevelScreen", "Caricamento mappa: " + effectiveMapPath);

        TilemapActor tma = new TilemapActor(effectiveMapPath, mainStage);

        // Solidi
        for (MapObject obj : tma.getRectangleList("solido"))
        {
            if (obj instanceof RectangleMapObject)
            {
                Rectangle rect = ((RectangleMapObject) obj).getRectangle();
                new Object(rect.x, rect.y, rect.width, rect.height, mainStage);
                continue;
            }

            if (obj instanceof PolygonMapObject)
            {
                addSolidTriangles(((PolygonMapObject) obj).getPolygon());
            }
        }

        // Punto di spawn — errore chiaro se mancante
        ArrayList<MapObject> startPoints = tma.getRectangleList("start");
        if (startPoints.isEmpty())
            throw new IllegalStateException(
                    "[LevelScreen] Nessun oggetto 'start' trovato in: " + mapPath
                            + "\nControlla che il layer Oggetti abbia un rettangolo con nome 'start'.");

        MapObject startPoint = startPoints.get(0);
        MapProperties startProps = startPoint.getProperties();
        pablo = new Pablo(
                (float) startProps.get("x"),
                (float) startProps.get("y"),
                mainStage
        );
        PlayerState.applyTo(pablo);
        if (spawnSide.equals("right")) {
            // Viene dalla mappa a destra → lo metti al bordo destro
            pablo.setX(BaseActor.getWorldBounds().width - pablo.getWidth() - 10f);
        } else if (spawnSide.equals("left")) {
            // Viene dalla mappa a sinistra → lo metti al bordo sinistro
            pablo.setX(10f);
        }
        pablo.setSoul(0);


        // -----------------------------------------------------------------------
        // UI — maschere HP
        // -----------------------------------------------------------------------
        maskTexture = loadTextureSafe(MASK_PATH, Color.WHITE);
        maskImages  = new Image[pablo.getMaxHealth()];

        Table maskRow = new Table();
        for (int i = 0; i < pablo.getMaxHealth(); i++)
        {
            maskImages[i] = new Image(maskTexture);
            maskImages[i].setColor(MASK_FULL);
            maskRow.add(maskImages[i]).size(MASK_W, MASK_H).padRight(MASK_PAD_RIGHT);
        }

        // -----------------------------------------------------------------------
        // UI — ricettacolo anima
        // -----------------------------------------------------------------------
        vesselTextures  = new Texture[VESSEL_STATES][];
        vesselDrawables = new TextureRegionDrawable[VESSEL_STATES][];

        vesselTextures[0]  = new Texture[1];
        vesselDrawables[0] = new TextureRegionDrawable[1];
        vesselTextures[0][0]  = createEmptyVesselTexture((int) VESSEL_SIZE);
        vesselDrawables[0][0] = new TextureRegionDrawable(
                new TextureRegion(vesselTextures[0][0]));

        for (int state = 1; state < VESSEL_STATES; state++)
        {
            vesselTextures[state]  = new Texture[FRAMES_PER_STATE];
            vesselDrawables[state] = new TextureRegionDrawable[FRAMES_PER_STATE];

            for (int frame = 0; frame < FRAMES_PER_STATE; frame++)
            {
                String path = SOUL_DIR + state + "_" + (frame + 1) + ".png";
                Color fb = new Color(state / 8f, state / 8f, state / 8f, 1f);
                vesselTextures[state][frame]  = loadTextureSafe(path, fb);
                vesselDrawables[state][frame] = new TextureRegionDrawable(
                        new TextureRegion(vesselTextures[state][frame]));
            }
        }

        vesselImage = new Image(vesselDrawables[0][0]);

        // Layout UI
        uiTable.top().left();
        uiTable.add(maskRow).left().padTop(HUD_PAD_TOP).padLeft(14).row();
        uiTable.add(vesselImage).size(VESSEL_SIZE, VESSEL_SIZE)
                .left().padTop(VESSEL_PAD_TOP).padLeft(VESSEL_PAD_LEFT).row();

        // -----------------------------------------------------------------------
        // Nemici comuni
        // -----------------------------------------------------------------------
        spawnEnemiesFromMap(tma);

        // -----------------------------------------------------------------------
        // Trigger boss e spawn point
        // -----------------------------------------------------------------------
        setupBossTrigger(tma);

        // -----------------------------------------------------------------------
        // FalseKnight — opzionale
        // -----------------------------------------------------------------------
        if (bossTrigger == null)
        {
            spawnFalseKnightIfPresent();
        }
        else
        {
            Gdx.app.log("LevelScreen", "FalseKnight in attesa di conferma dialogo.");
        }

        // Z-order
        tma.toBack();
        for (BaseActor eActor : BaseActor.getList(mainStage, Enemy.class.getName()))
            eActor.toFront();
        if (falseKnight != null) falseKnight.toFront();
        pablo.toFront();
    }

    // -----------------------------------------------------------------------
    // spawnEnemiesFromMap()
    // -----------------------------------------------------------------------
    private void spawnEnemiesFromMap(TilemapActor tma)
    {
        spawnEnemyType(tma, "Crawlid");
        spawnEnemyType(tma, "Tiktik");
        spawnEnemyType(tma, "Vengefly");
        spawnEnemyType(tma, "HuskBully");
        spawnEnemyType(tma, "HuskHornhead");
        spawnEnemyType(tma, "HuskWarrior");
    }

    private void spawnEnemyType(TilemapActor tma, String type)
    {
        ArrayList<MapObject> objects = tma.getRectangleList(type);

        for (MapObject obj : objects)
        {
            MapProperties props = obj.getProperties();
            float x = (float) props.get("x");
            float y = (float) props.get("y");

            Enemy enemy = createEnemy(type, x, y);
            enemy.toFront();
        }
    }

    private Enemy createEnemy(String type, float x, float y)
    {
        switch (type)
        {
            case "Crawlid":      return new Crawlid(x, y, mainStage, pablo);
            case "Tiktik":       return new Tiktik(x, y, mainStage, pablo);
            case "Vengefly":     return new Vengefly(x, y, mainStage, pablo);
            case "HuskBully":    return new HuskBully(x, y, mainStage, pablo);
            case "HuskHornhead": return new HuskHornhead(x, y, mainStage, pablo);
            case "HuskWarrior":  return new HuskWarrior(x, y, mainStage, pablo);
            default: throw new IllegalArgumentException("Tipo nemico sconosciuto: " + type);
        }
    }

    // -----------------------------------------------------------------------
    // update()
    // -----------------------------------------------------------------------
    public void update(float dt)
    {
        SoundManager.get().update(dt);

        // Maschere HP
        int health = pablo.getHealth();
        for (int i = 0; i < maskImages.length; i++)
            maskImages[i].setColor(i < health ? MASK_FULL : MASK_EMPTY);

        // Ricettacolo anima
        updateVessel(dt);

        // Void fall
        if (pablo.getY() <= 2f && !pablo.isOnSolid())
        {
            voidTimer += dt;
            if (voidTimer >= VOID_RESPAWN_DELAY)
            {
                pablo.respawn();
                voidTimer = 0f;
            }
            return;
        }
        else
        {
            voidTimer = 0f;
        }

        // Collisioni player <-> solidi
        for (BaseActor actor : BaseActor.getList(mainStage, Object.class.getName()))
        {
            Object oggetto = (Object) actor;
            if (pablo.overlaps(oggetto) && oggetto.isEnable())
            {
                Vector2 offset = pablo.preventOverlap(oggetto);
                if (offset != null)
                {
                    if (Math.abs(offset.x) > Math.abs(offset.y))
                        pablo.velocityVec.x = 0;
                    else
                        pablo.velocityVec.y = 0;
                }
            }
        }

        // Collisioni nemici <-> solidi
        for (BaseActor eActor : BaseActor.getList(mainStage, Enemy.class.getName()))
        {
            Enemy enemy = (Enemy) eActor;
            for (BaseActor sActor : BaseActor.getList(mainStage, Object.class.getName()))
            {
                Object solid = (Object) sActor;
                if (enemy.overlaps(solid) && solid.isEnable())
                {
                    Vector2 offset = enemy.preventOverlap(solid);
                    if (offset != null)
                    {
                        if (Math.abs(offset.x) > Math.abs(offset.y))
                        {
                            enemy.velocityVec.x = 0;
                            enemy.onWallHit();
                        }
                        else
                        {
                            enemy.velocityVec.y = 0;
                        }
                    }
                }
            }
        }

        // Screen shake
        if (shakeDuration > 0)
        {
            shakeDuration -= dt;
            Camera cam = mainStage.getCamera();
            cam.position.y += (Math.random() > 0.5 ? 1 : -1) * shakeIntensity;
            cam.update();
        }

        // Trigger dialogo boss
        if (bossTrigger != null && !bossFightStarted && !bossDialogOpen)
        {
            if (pablo.overlaps(bossTrigger) && Gdx.input.isKeyJustPressed(Input.Keys.E))
                openBossDialog();
        }

        // FalseKnight — solo se presente nella mappa
        if (falseKnight != null && !falseKnight.isDead())
        {
            for (BaseActor sActor : BaseActor.getList(mainStage, Object.class.getName()))
            {
                Object solid = (Object) sActor;
                if (falseKnight.overlaps(solid) && solid.isEnable())
                {
                    Vector2 offset = falseKnight.preventOverlap(solid);
                    if (offset != null)
                    {
                        if (Math.abs(offset.x) > Math.abs(offset.y))
                        {
                            falseKnight.velocityVec.x = 0;
                            falseKnight.onWallHit();
                        }
                        else
                        {
                            falseKnight.velocityVec.y = 0;
                            falseKnight.onGroundLanded();
                        }
                    }
                }
            }

            if (falseKnight.maceOverlapsPablo())
                pablo.takeDamage(1);
        }

        // Transizione mappa destra
        MapGraph.MapNode node = MapGraph.get(mapPath);
        if (node != null && node.rightNeighbor != null) {
            if (pablo.getX() + pablo.getWidth() >= BaseActor.getWorldBounds().width - 2f) {
                PlayerState.saveFrom(pablo);
                BaseGame.setActiveScreen(new LevelScreen(node.rightNeighbor, "left"));
            }
        }
        // Transizione mappa sinistra
        if (node != null && node.leftNeighbor != null) {
            if (pablo.getX() <= 2f) {
                PlayerState.saveFrom(pablo);
                BaseGame.setActiveScreen(new LevelScreen(node.leftNeighbor, "right"));
            }
        }

        logEnemyRuntimeState(dt);
    }

    private void logEnemyRuntimeState(float dt)
    {
        if (enemyRuntimeLogCount >= 5) return;
        enemyRuntimeLogTimer += dt;
        if (enemyRuntimeLogTimer < 1f) return;

        enemyRuntimeLogTimer = 0f;
        enemyRuntimeLogCount++;

        Camera cam = mainStage.getCamera();
        Gdx.app.log("EnemyRuntime", "sample=" + enemyRuntimeLogCount
                + " camera=" + cam.position.x + "," + cam.position.y
                + " enemies=" + BaseActor.count(mainStage, Enemy.class.getName()));
    }

    // -----------------------------------------------------------------------
    // updateVessel()
    // -----------------------------------------------------------------------
    private void updateVessel(float dt)
    {
        int soul = pablo.getSoul();
        int vesselState = getVesselStateForSoul(soul);

        if (vesselState != lastVesselState)
        {
            vesselAnimTime  = 0f;
            lastVesselState = vesselState;
        }

        if (vesselState == 0)
        {
            vesselImage.setDrawable(vesselDrawables[0][0]);
            return;
        }

        vesselAnimTime += dt;
        int   frameCount     = vesselDrawables[vesselState].length;
        float totalDuration  = FRAME_DURATION * frameCount;
        vesselAnimTime %= totalDuration;

        int frameIndex = (int)(vesselAnimTime / FRAME_DURATION);
        frameIndex = Math.min(frameIndex, frameCount - 1);

        vesselImage.setDrawable(vesselDrawables[vesselState][frameIndex]);
    }

    // -----------------------------------------------------------------------
    // keyDown()
    // -----------------------------------------------------------------------
    public boolean keyDown(int keyCode)
    {
        if (bossDialogOpen)
        {
            if (keyCode == Input.Keys.ENTER)
            {
                closeBossDialog();
                if (bossTeleportPoint != null)
                {
                    pablo.setPosition(bossTeleportPoint.x, bossTeleportPoint.y);
                    pablo.velocityVec.set(0, 0);
                }
                spawnFalseKnightIfPresent();
                return true;
            }
            if (keyCode == Input.Keys.ESCAPE)
            {
                closeBossDialog();
                return true;
            }
        }

        if (keyCode == Input.Keys.ESCAPE || keyCode == Input.Keys.P)
        {
            BaseGame.setActiveScreen(new PauseScreen(this));
            return true;
        }
        if (keyCode == Input.Keys.K) { pablo.takeDamage(1); return true; }
        if (keyCode == Input.Keys.O)
        {
            if (falseKnight != null) falseKnight.takeDamage(1);
            return true;
        }
        if (keyCode == Input.Keys.L) { bumpSoulToNextVesselState(); return true; }

        if (keyCode == Input.Keys.SPACE || keyCode == Input.Keys.W)
            if (pablo.isOnSolid()) pablo.jump();

        return false;
    }

    // -----------------------------------------------------------------------
    // Boss dialog / trigger
    // -----------------------------------------------------------------------
    private void setupBossTrigger(TilemapActor tma)
    {
        ArrayList<MapObject> tpObjects = tma.getRectangleList("tp");
        if (!tpObjects.isEmpty())
        {
            MapObject tpObj = tpObjects.get(0);
            if (tpObj instanceof RectangleMapObject)
            {
                Rectangle rect = ((RectangleMapObject) tpObj).getRectangle();
                bossTrigger = new BaseActor(rect.x, rect.y, mainStage);
                bossTrigger.setSize(rect.width, rect.height);
                bossTrigger.setBoundaryRectangle();
                bossTrigger.setVisible(false);
            }
        }

        ArrayList<MapObject> spawnTpObjects = tma.getRectangleList("spawntp");
        if (!spawnTpObjects.isEmpty())
        {
            MapObject sp = spawnTpObjects.get(0);
            MapProperties props = sp.getProperties();
            bossTeleportPoint = new Vector2((float) props.get("x"), (float) props.get("y"));
        }

        ArrayList<MapObject> falseKnightPoints = tma.getRectangleList("FalseKnight");
        if (!falseKnightPoints.isEmpty())
        {
            MapObject fkPoint = falseKnightPoints.get(0);
            MapProperties fkProps = fkPoint.getProperties();
            bossSpawnPoint = new Vector2((float) fkProps.get("x"), (float) fkProps.get("y"));
        }
    }

    private void spawnFalseKnightIfPresent()
    {
        if (bossSpawnPoint == null)
        {
            Gdx.app.log("LevelScreen", "FalseKnight non presente in questa mappa — skip.");
            return;
        }

        if (falseKnight != null) return;
        falseKnight = new FalseKnight(bossSpawnPoint.x, bossSpawnPoint.y, mainStage, pablo);
        falseKnight.setScreenShakeCallback(() -> shakeDuration = 0.15f);
        falseKnight.toFront();
        bossFightStarted = true;
        Gdx.app.log("LevelScreen", "FalseKnight spawned at " + bossSpawnPoint.x + "," + bossSpawnPoint.y);
    }

    private void openBossDialog()
    {
        if (bossDialog == null) buildBossDialog();
        bossDialog.setVisible(true);
        bossDialogOpen = true;
    }

    private void closeBossDialog()
    {
        if (bossDialog != null) bossDialog.setVisible(false);
        bossDialogOpen = false;
    }

    private void buildBossDialog()
    {
        dialogTexture = loadTextureSafe("assets/dialog.png", new Color(0f, 0f, 0f, 0.75f));
        dialogFont = new BitmapFont();
        dialogFont.getData().setScale(1.1f);

        Pixmap upPix = new Pixmap(1, 1, Pixmap.Format.RGBA8888);
        upPix.setColor(new Color(0.25f, 0.25f, 0.25f, 0.9f));
        upPix.fill();
        dialogBtnUpTexture = new Texture(upPix);
        upPix.dispose();

        Pixmap downPix = new Pixmap(1, 1, Pixmap.Format.RGBA8888);
        downPix.setColor(new Color(0.4f, 0.4f, 0.4f, 0.95f));
        downPix.fill();
        dialogBtnDownTexture = new Texture(downPix);
        downPix.dispose();

        TextButtonStyle btnStyle = new TextButtonStyle();
        btnStyle.font = dialogFont;
        btnStyle.up = new TextureRegionDrawable(new TextureRegion(dialogBtnUpTexture));
        btnStyle.down = new TextureRegionDrawable(new TextureRegion(dialogBtnDownTexture));
        btnStyle.over = btnStyle.down;

        LabelStyle labelStyle = new LabelStyle(dialogFont, Color.WHITE);

        Label message = new Label(
                "Questa è la tua prova finale, vuoi affrontare il boss?",
                labelStyle);
        message.setWrap(true);
        message.setAlignment(Align.center);

        TextButton yesBtn = new TextButton("SI", btnStyle);
        TextButton noBtn  = new TextButton("NO", btnStyle);

        yesBtn.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor)
            {
                closeBossDialog();
                if (bossTeleportPoint != null)
                {
                    pablo.setPosition(bossTeleportPoint.x, bossTeleportPoint.y);
                    pablo.velocityVec.set(0, 0);
                }
                spawnFalseKnightIfPresent();
            }
        });

        noBtn.addListener(new ChangeListener() {
            @Override
            public void changed(ChangeEvent event, Actor actor)
            {
                closeBossDialog();
            }
        });

        Table box = new Table();
        box.setBackground(new TextureRegionDrawable(new TextureRegion(dialogTexture)));
        box.pad(24f);
        box.add(message).width(520).center().row();

        Table buttons = new Table();
        buttons.add(yesBtn).width(120).height(36).padRight(20);
        buttons.add(noBtn).width(120).height(36);
        box.add(buttons).padTop(16).center();

        bossDialog = new Table();
        bossDialog.setFillParent(true);
        bossDialog.center();
        bossDialog.add(box).center();
        bossDialog.setVisible(false);
        uiStage.addActor(bossDialog);
    }

    // -----------------------------------------------------------------------
    // dispose()
    // -----------------------------------------------------------------------
    @Override
    public void dispose()
    {
        super.dispose();
        if (maskTexture != null) maskTexture.dispose();
        if (vesselTextures != null)
            for (Texture[] row : vesselTextures)
                if (row != null)
                    for (Texture t : row)
                        if (t != null) t.dispose();
        if (dialogTexture != null) dialogTexture.dispose();
        if (dialogFont != null) dialogFont.dispose();
        if (dialogBtnUpTexture != null) dialogBtnUpTexture.dispose();
        if (dialogBtnDownTexture != null) dialogBtnDownTexture.dispose();
    }

    private void addSolidTriangles(Polygon polygon)
    {
        float[] vertices = polygon.getVertices();
        if (vertices == null || vertices.length < 6) return;

        EarClippingTriangulator triangulator = new EarClippingTriangulator();
        ShortArray indices = triangulator.computeTriangles(vertices);
        Rectangle bounds = polygon.getBoundingRectangle();

        for (int i = 0; i < indices.size; i += 3)
        {
            int i1 = indices.get(i) * 2;
            int i2 = indices.get(i + 1) * 2;
            int i3 = indices.get(i + 2) * 2;

            float[] tri = new float[] {
                    vertices[i1], vertices[i1 + 1],
                    vertices[i2], vertices[i2 + 1],
                    vertices[i3], vertices[i3 + 1]
            };

            Object solid = new Object(polygon.getX(), polygon.getY(), bounds.width, bounds.height, mainStage);
            solid.setBoundaryPolygon(tri);
        }
    }
}

// MenuScreen.java — modificato per integrare SoundManager
// DIFF:
//   initialize()  → avvia la musica del menu
//   keyDown()     → SFX selezione e conferma
//   updateSelection() → SFX select ad ogni cambio voce

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.GL20;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.BitmapFont;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import com.badlogic.gdx.graphics.g2d.freetype.FreeTypeFontGenerator;
import com.badlogic.gdx.graphics.g2d.freetype.FreeTypeFontGenerator.FreeTypeFontParameter;
import com.badlogic.gdx.graphics.glutils.ShapeRenderer;
import com.badlogic.gdx.scenes.scene2d.Actor;
import com.badlogic.gdx.scenes.scene2d.ui.Label;
import com.badlogic.gdx.scenes.scene2d.ui.Label.LabelStyle;
import com.badlogic.gdx.scenes.scene2d.ui.Table;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton.TextButtonStyle;
import com.badlogic.gdx.scenes.scene2d.utils.ChangeListener;
import pablo.framework.BaseGame;
import pablo.framework.BaseScreen;

public class MenuScreen extends BaseScreen
{
    private static final String BG_PATH   = "assets/MenùBG.png";
    private static final String FONT_PATH = "assets/TrajanPro-Regular.ttf";

    private static final Color COL_START_NORMAL = Color.WHITE;
    private static final Color COL_START_SEL    = new Color(0.75f, 1f, 0.75f, 1f);
    private static final Color COL_START_DOWN   = new Color(0.4f, 0.9f, 0.4f, 1f);
    private static final Color COL_OTHER_NORMAL = new Color(0.78f, 0.78f, 0.78f, 1f);
    private static final Color COL_OTHER_SEL    = Color.WHITE;
    private static final Color COL_SEP          = new Color(1f, 1f, 1f, 0.55f);
    private static final Color COL_ICON_NORMAL  = Color.WHITE;
    private static final Color COL_ICON_SEL     = new Color(0.4f, 1f, 0.4f, 1f);
    private static final String ICON_TEXT       = " \u2767 ";

    private static final int MENU_COUNT = 3;
    private int selectedIndex = 0;
    private TextButton[] buttons;
    private Label[] iconLeft;
    private Label[] iconRight;

    private static final int TITLE_FRAMES = 240;
    private static final float TITLE_FPS = 30f;
    private static final float TITLE_FRAME_DURATION = 1f / TITLE_FPS;

    private float titleElapsedTime = 0f;
    private int titleFrameIndex = -1;
    private Texture titleFrame;

    private SpriteBatch   batch;
    private ShapeRenderer shapeRenderer;
    private Texture       background;
    private BitmapFont    fontStart;
    private BitmapFont    fontOther;

    private TextButtonStyle styleStart;
    private TextButtonStyle styleOther;
    private TextButtonStyle styleStartSel;
    private TextButtonStyle styleOtherSel;

    private float separatorY  = -1;
    private float separatorX1, separatorX2;

    public void initialize()
    {
        batch         = new SpriteBatch();
        shapeRenderer = new ShapeRenderer();
        background    = new Texture(Gdx.files.internal(BG_PATH));

        FreeTypeFontGenerator gen = new FreeTypeFontGenerator(
                Gdx.files.internal(FONT_PATH));

        FreeTypeFontParameter pStart = new FreeTypeFontParameter();
        pStart.size = 46; pStart.color = COL_START_NORMAL;
        pStart.borderWidth = 1.5f; pStart.borderColor = new Color(0,0,0,0.7f);
        fontStart = gen.generateFont(pStart);

        FreeTypeFontParameter pOther = new FreeTypeFontParameter();
        pOther.size = 28; pOther.color = COL_OTHER_NORMAL;
        pOther.borderWidth = 1.2f; pOther.borderColor = new Color(0,0,0,0.6f);
        fontOther = gen.generateFont(pOther);

        gen.dispose();

        styleStart    = makeStyle(fontStart, COL_START_NORMAL, COL_START_SEL,  COL_START_DOWN);
        styleOther    = makeStyle(fontOther, COL_OTHER_NORMAL, COL_OTHER_SEL,  COL_OTHER_SEL);
        styleStartSel = makeStyle(fontStart, COL_START_SEL,   COL_START_SEL,  COL_START_DOWN);
        styleOtherSel = makeStyle(fontOther, COL_OTHER_SEL,   COL_OTHER_SEL,  COL_OTHER_SEL);

        LabelStyle styleDecorStart = new LabelStyle(); styleDecorStart.font = fontStart;
        LabelStyle styleDecorOther = new LabelStyle(); styleDecorOther.font = fontOther;

        TextButton startBtn = new TextButton("INIZIA", styleStart);
        startBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
                BaseGame.setActiveScreen(new LevelScreen());
            }
        });

        TextButton optionsBtn = new TextButton("OPZIONI", styleOther);
        optionsBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
                BaseGame.setActiveScreen(new OptionsScreen(MenuScreen.this, MenuScreen.this));
            }
        });

        TextButton exitBtn = new TextButton("ESCI", styleOther);
        exitBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_BACK);
                Gdx.app.exit();
            }
        });

        buttons = new TextButton[]{ startBtn, optionsBtn, exitBtn };
        iconLeft  = new Label[MENU_COUNT];
        iconRight = new Label[MENU_COUNT];

        iconLeft[0]  = new Label(ICON_TEXT, styleDecorStart);
        iconRight[0] = new Label(ICON_TEXT, styleDecorStart);
        iconLeft[1]  = new Label(ICON_TEXT, styleDecorOther);
        iconRight[1] = new Label(ICON_TEXT, styleDecorOther);
        iconLeft[2]  = new Label(ICON_TEXT, styleDecorOther);
        iconRight[2] = new Label(ICON_TEXT, styleDecorOther);

        uiTable.bottom().right();
        uiTable.padBottom(80).padRight(90);

        Table startRow = new Table();
        startRow.add(iconLeft[0]);
        startRow.add(startBtn).padLeft(6).padRight(6);
        startRow.add(iconRight[0]);
        uiTable.add(startRow).right().padBottom(10).row();

        uiTable.add(new Label("", styleDecorOther)).height(2).padBottom(18).row();

        Table optionsRow = new Table();
        optionsRow.add(iconLeft[1]);
        optionsRow.add(optionsBtn).padLeft(6).padRight(6);
        optionsRow.add(iconRight[1]);
        uiTable.add(optionsRow).right().padBottom(12).row();

        Table exitRow = new Table();
        exitRow.add(iconLeft[2]);
        exitRow.add(exitBtn).padLeft(6).padRight(6);
        exitRow.add(iconRight[2]);
        uiTable.add(exitRow).right().row();

        updateSelection();

        // ── OST: avvia la musica del menu ──────────────────────────────────
        SoundManager.get().playMusic(SoundManager.Track.MENU);
    }

    @Override
    public void render(float dt)
    {
        dt = Math.min(dt, 1 / 30f);
        titleElapsedTime += dt;

        Gdx.gl.glClearColor(0f, 0f, 0f, 1f);
        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

        drawBackground();

        uiStage.act(dt);
        uiStage.draw();

        if (separatorY < 0) computeSeparator();
        if (separatorY >= 0)
        {
            uiStage.getViewport().apply();
            Gdx.gl.glEnable(GL20.GL_BLEND);
            shapeRenderer.begin(ShapeRenderer.ShapeType.Filled);
            shapeRenderer.setColor(COL_SEP);
            shapeRenderer.rectLine(separatorX1, separatorY, separatorX2, separatorY, 1.5f);
            shapeRenderer.end();
            Gdx.gl.glDisable(GL20.GL_BLEND);
        }
    }

    @Override
    public void drawFrozen()
    {
        drawBackground();
        uiStage.getViewport().apply();
        uiStage.draw();
    }

    private void drawBackground()
    {
        mainStage.getViewport().apply();
        float viewportWidth  = mainStage.getViewport().getWorldWidth();
        float viewportHeight = mainStage.getViewport().getWorldHeight();

        int frameIndex = ((int)(titleElapsedTime / TITLE_FRAME_DURATION) % TITLE_FRAMES) + 1;
        if (frameIndex != titleFrameIndex)
        {
            String path = String.format("assets/Titolo/frame_%04d.png", frameIndex);
            if (Gdx.files.internal(path).exists())
            {
                Texture next = new Texture(Gdx.files.internal(path));
                if (titleFrame != null) titleFrame.dispose();
                titleFrame = next;
                titleFrameIndex = frameIndex;
            }
        }

        Texture toDraw = (titleFrame != null) ? titleFrame : background;

        batch.setProjectionMatrix(mainStage.getCamera().combined);
        batch.begin();
        batch.draw(toDraw, 0, 0, viewportWidth, viewportHeight);
        batch.end();
    }

    public void update(float dt) { }

    @Override
    public boolean keyDown(int keycode)
    {
        if (keycode == Input.Keys.DOWN || keycode == Input.Keys.S)
        {
            selectedIndex = (selectedIndex + 1) % MENU_COUNT;
            updateSelection();
            return true;
        }
        if (keycode == Input.Keys.UP || keycode == Input.Keys.W)
        {
            selectedIndex = (selectedIndex - 1 + MENU_COUNT) % MENU_COUNT;
            updateSelection();
            return true;
        }
        if (keycode == Input.Keys.ENTER || keycode == Input.Keys.SPACE)
        {
            SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
            activateSelected();
            return true;
        }
        return false;
    }

    @Override
    public void resize(int width, int height)
    {
        super.resize(width, height);
        separatorY = -1;
    }

    private void updateSelection()
    {
        for (int i = 0; i < buttons.length; i++)
        {
            if (i == 0)
                buttons[i].setStyle(i == selectedIndex ? styleStartSel : styleStart);
            else
                buttons[i].setStyle(i == selectedIndex ? styleOtherSel : styleOther);

            Color iconColor = (i == selectedIndex) ? COL_ICON_SEL : COL_ICON_NORMAL;
            iconLeft[i].setColor(iconColor);
            iconRight[i].setColor(iconColor);
        }
        // SFX: cambio selezione
        SoundManager.get().playSfx(SoundManager.Sfx.UI_SELECT);
    }

    private void activateSelected()
    {
        switch (selectedIndex)
        {
            case 0: BaseGame.setActiveScreen(new LevelScreen());             break;
            case 1: BaseGame.setActiveScreen(new OptionsScreen(this, this)); break;
            case 2: Gdx.app.exit();                                           break;
        }
    }

    private TextButtonStyle makeStyle(BitmapFont font, Color normal, Color over, Color down)
    {
        TextButtonStyle s = new TextButtonStyle();
        s.font = font; s.fontColor = normal; s.overFontColor = over; s.downFontColor = down;
        return s;
    }

    private void computeSeparator()
    {
        uiStage.getViewport().apply();
        float tableW = uiTable.getPrefWidth();
        float tableX = uiTable.getX();
        separatorX1  = tableX + 16f;
        separatorX2  = tableX + tableW - 16f;
        separatorY   = uiTable.getY() + uiTable.getPrefHeight() - 80f;
    }

    @Override
    public void dispose()
    {
        super.dispose();
        batch.dispose();
        shapeRenderer.dispose();
        background.dispose();
        if (titleFrame != null) titleFrame.dispose();
        fontStart.dispose();
        fontOther.dispose();
    }
}

// MenuScreen.java — modificato per integrare SoundManager
// DIFF:
//   initialize()  → avvia la musica del menu
//   keyDown()     → SFX selezione e conferma
//   updateSelection() → SFX select ad ogni cambio voce

package pablo;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.GL20;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.BitmapFont;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import com.badlogic.gdx.graphics.g2d.freetype.FreeTypeFontGenerator;
import com.badlogic.gdx.graphics.g2d.freetype.FreeTypeFontGenerator.FreeTypeFontParameter;
import com.badlogic.gdx.graphics.glutils.ShapeRenderer;
import com.badlogic.gdx.scenes.scene2d.Actor;
import com.badlogic.gdx.scenes.scene2d.ui.Label;
import com.badlogic.gdx.scenes.scene2d.ui.Label.LabelStyle;
import com.badlogic.gdx.scenes.scene2d.ui.Table;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton;
import com.badlogic.gdx.scenes.scene2d.ui.TextButton.TextButtonStyle;
import com.badlogic.gdx.scenes.scene2d.utils.ChangeListener;
import pablo.framework.BaseGame;
import pablo.framework.BaseScreen;

public class MenuScreen extends BaseScreen
{
    private static final String BG_PATH   = "assets/MenùBG.png";
    private static final String FONT_PATH = "assets/TrajanPro-Regular.ttf";

    private static final Color COL_START_NORMAL = Color.WHITE;
    private static final Color COL_START_SEL    = new Color(0.75f, 1f, 0.75f, 1f);
    private static final Color COL_START_DOWN   = new Color(0.4f, 0.9f, 0.4f, 1f);
    private static final Color COL_OTHER_NORMAL = new Color(0.78f, 0.78f, 0.78f, 1f);
    private static final Color COL_OTHER_SEL    = Color.WHITE;
    private static final Color COL_SEP          = new Color(1f, 1f, 1f, 0.55f);
    private static final Color COL_ICON_NORMAL  = Color.WHITE;
    private static final Color COL_ICON_SEL     = new Color(0.4f, 1f, 0.4f, 1f);
    private static final String ICON_TEXT       = " \u2767 ";

    private static final int MENU_COUNT = 3;
    private int selectedIndex = 0;
    private TextButton[] buttons;
    private Label[] iconLeft;
    private Label[] iconRight;

    private static final int TITLE_FRAMES = 240;
    private static final float TITLE_FPS = 30f;
    private static final float TITLE_FRAME_DURATION = 1f / TITLE_FPS;

    private float titleElapsedTime = 0f;
    private int titleFrameIndex = -1;
    private Texture titleFrame;

    private SpriteBatch   batch;
    private ShapeRenderer shapeRenderer;
    private Texture       background;
    private BitmapFont    fontStart;
    private BitmapFont    fontOther;

    private TextButtonStyle styleStart;
    private TextButtonStyle styleOther;
    private TextButtonStyle styleStartSel;
    private TextButtonStyle styleOtherSel;

    private float separatorY  = -1;
    private float separatorX1, separatorX2;

    public void initialize()
    {
        batch         = new SpriteBatch();
        shapeRenderer = new ShapeRenderer();
        background    = new Texture(Gdx.files.internal(BG_PATH));

        FreeTypeFontGenerator gen = new FreeTypeFontGenerator(
                Gdx.files.internal(FONT_PATH));

        FreeTypeFontParameter pStart = new FreeTypeFontParameter();
        pStart.size = 46; pStart.color = COL_START_NORMAL;
        pStart.borderWidth = 1.5f; pStart.borderColor = new Color(0,0,0,0.7f);
        fontStart = gen.generateFont(pStart);

        FreeTypeFontParameter pOther = new FreeTypeFontParameter();
        pOther.size = 28; pOther.color = COL_OTHER_NORMAL;
        pOther.borderWidth = 1.2f; pOther.borderColor = new Color(0,0,0,0.6f);
        fontOther = gen.generateFont(pOther);

        gen.dispose();

        styleStart    = makeStyle(fontStart, COL_START_NORMAL, COL_START_SEL,  COL_START_DOWN);
        styleOther    = makeStyle(fontOther, COL_OTHER_NORMAL, COL_OTHER_SEL,  COL_OTHER_SEL);
        styleStartSel = makeStyle(fontStart, COL_START_SEL,   COL_START_SEL,  COL_START_DOWN);
        styleOtherSel = makeStyle(fontOther, COL_OTHER_SEL,   COL_OTHER_SEL,  COL_OTHER_SEL);

        LabelStyle styleDecorStart = new LabelStyle(); styleDecorStart.font = fontStart;
        LabelStyle styleDecorOther = new LabelStyle(); styleDecorOther.font = fontOther;

        TextButton startBtn = new TextButton("INIZIA", styleStart);
        startBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
                BaseGame.setActiveScreen(new LevelScreen());
            }
        });

        TextButton optionsBtn = new TextButton("OPZIONI", styleOther);
        optionsBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
                BaseGame.setActiveScreen(new OptionsScreen(MenuScreen.this, MenuScreen.this));
            }
        });

        TextButton exitBtn = new TextButton("ESCI", styleOther);
        exitBtn.addListener(new ChangeListener() {
            public void changed(ChangeEvent e, Actor a) {
                SoundManager.get().playSfx(SoundManager.Sfx.UI_BACK);
                Gdx.app.exit();
            }
        });

        buttons = new TextButton[]{ startBtn, optionsBtn, exitBtn };
        iconLeft  = new Label[MENU_COUNT];
        iconRight = new Label[MENU_COUNT];

        iconLeft[0]  = new Label(ICON_TEXT, styleDecorStart);
        iconRight[0] = new Label(ICON_TEXT, styleDecorStart);
        iconLeft[1]  = new Label(ICON_TEXT, styleDecorOther);
        iconRight[1] = new Label(ICON_TEXT, styleDecorOther);
        iconLeft[2]  = new Label(ICON_TEXT, styleDecorOther);
        iconRight[2] = new Label(ICON_TEXT, styleDecorOther);

        uiTable.bottom().right();
        uiTable.padBottom(80).padRight(90);

        Table startRow = new Table();
        startRow.add(iconLeft[0]);
        startRow.add(startBtn).padLeft(6).padRight(6);
        startRow.add(iconRight[0]);
        uiTable.add(startRow).right().padBottom(10).row();

        uiTable.add(new Label("", styleDecorOther)).height(2).padBottom(18).row();

        Table optionsRow = new Table();
        optionsRow.add(iconLeft[1]);
        optionsRow.add(optionsBtn).padLeft(6).padRight(6);
        optionsRow.add(iconRight[1]);
        uiTable.add(optionsRow).right().padBottom(12).row();

        Table exitRow = new Table();
        exitRow.add(iconLeft[2]);
        exitRow.add(exitBtn).padLeft(6).padRight(6);
        exitRow.add(iconRight[2]);
        uiTable.add(exitRow).right().row();

        updateSelection();

        // ── OST: avvia la musica del menu ──────────────────────────────────
        SoundManager.get().playMusic(SoundManager.Track.MENU);
    }

    @Override
    public void render(float dt)
    {
        dt = Math.min(dt, 1 / 30f);
        titleElapsedTime += dt;

        Gdx.gl.glClearColor(0f, 0f, 0f, 1f);
        Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);

        drawBackground();

        uiStage.act(dt);
        uiStage.draw();

        if (separatorY < 0) computeSeparator();
        if (separatorY >= 0)
        {
            uiStage.getViewport().apply();
            Gdx.gl.glEnable(GL20.GL_BLEND);
            shapeRenderer.begin(ShapeRenderer.ShapeType.Filled);
            shapeRenderer.setColor(COL_SEP);
            shapeRenderer.rectLine(separatorX1, separatorY, separatorX2, separatorY, 1.5f);
            shapeRenderer.end();
            Gdx.gl.glDisable(GL20.GL_BLEND);
        }
    }

    @Override
    public void drawFrozen()
    {
        drawBackground();
        uiStage.getViewport().apply();
        uiStage.draw();
    }

    private void drawBackground()
    {
        mainStage.getViewport().apply();
        float viewportWidth  = mainStage.getViewport().getWorldWidth();
        float viewportHeight = mainStage.getViewport().getWorldHeight();

        int frameIndex = ((int)(titleElapsedTime / TITLE_FRAME_DURATION) % TITLE_FRAMES) + 1;
        if (frameIndex != titleFrameIndex)
        {
            String path = String.format("assets/Titolo/frame_%04d.png", frameIndex);
            if (Gdx.files.internal(path).exists())
            {
                Texture next = new Texture(Gdx.files.internal(path));
                if (titleFrame != null) titleFrame.dispose();
                titleFrame = next;
                titleFrameIndex = frameIndex;
            }
        }

        Texture toDraw = (titleFrame != null) ? titleFrame : background;

        batch.setProjectionMatrix(mainStage.getCamera().combined);
        batch.begin();
        batch.draw(toDraw, 0, 0, viewportWidth, viewportHeight);
        batch.end();
    }

    public void update(float dt)
    {
        SoundManager.get().update(dt);
    }

    @Override
    public boolean keyDown(int keycode)
    {
        if (keycode == Input.Keys.DOWN || keycode == Input.Keys.S)
        {
            selectedIndex = (selectedIndex + 1) % MENU_COUNT;
            updateSelection();
            return true;
        }
        if (keycode == Input.Keys.UP || keycode == Input.Keys.W)
        {
            selectedIndex = (selectedIndex - 1 + MENU_COUNT) % MENU_COUNT;
            updateSelection();
            return true;
        }
        if (keycode == Input.Keys.ENTER || keycode == Input.Keys.SPACE)
        {
            SoundManager.get().playSfx(SoundManager.Sfx.UI_CONFIRM);
            activateSelected();
            return true;
        }
        return false;
    }

    @Override
    public void resize(int width, int height)
    {
        super.resize(width, height);
        separatorY = -1;
    }

    private void updateSelection()
    {
        for (int i = 0; i < buttons.length; i++)
        {
            if (i == 0)
                buttons[i].setStyle(i == selectedIndex ? styleStartSel : styleStart);
            else
                buttons[i].setStyle(i == selectedIndex ? styleOtherSel : styleOther);

            Color iconColor = (i == selectedIndex) ? COL_ICON_SEL : COL_ICON_NORMAL;
            iconLeft[i].setColor(iconColor);
            iconRight[i].setColor(iconColor);
        }
        // SFX: cambio selezione
        SoundManager.get().playSfx(SoundManager.Sfx.UI_SELECT);
    }

    private void activateSelected()
    {
        switch (selectedIndex)
        {
            case 0: BaseGame.setActiveScreen(new LevelScreen());             break;
            case 1: BaseGame.setActiveScreen(new OptionsScreen(this, this)); break;
            case 2: Gdx.app.exit();                                           break;
        }
    }

    private TextButtonStyle makeStyle(BitmapFont font, Color normal, Color over, Color down)
    {
        TextButtonStyle s = new TextButtonStyle();
        s.font = font; s.fontColor = normal; s.overFontColor = over; s.downFontColor = down;
        return s;
    }

    private void computeSeparator()
    {
        uiStage.getViewport().apply();
        float tableW = uiTable.getPrefWidth();
        float tableX = uiTable.getX();
        separatorX1  = tableX + 16f;
        separatorX2  = tableX + tableW - 16f;
        separatorY   = uiTable.getY() + uiTable.getPrefHeight() - 80f;
    }

    @Override
    public void dispose()
    {
        super.dispose();
        batch.dispose();
        shapeRenderer.dispose();
        background.dispose();
        if (titleFrame != null) titleFrame.dispose();
        fontStart.dispose();
        fontOther.dispose();
    }
}

// Pablo.java

package pablo.entities.player;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.g2d.Animation;
import com.badlogic.gdx.math.MathUtils;
import com.badlogic.gdx.scenes.scene2d.Stage;
import pablo.Object;
import pablo.SoundManager;
import pablo.SoundManager.Sfx;
import pablo.framework.BaseActor;
import pablo.entities.combat.Hitbox;

public class Pablo extends BaseActor
{
    private Animation stand;
    private Animation walk;

    private float walkAcceleration;
    private float walkDeceleration;
    private float maxHorizontalSpeed;
    private float gravity;
    private float maxVerticalSpeed;

    // Health
    private int maxHealth;
    private int health;
    private boolean isDead = false;

    // Anima
    public  static final int MAX_SOUL      = 100;
    private static final int SOUL_PER_HEAL = 33;
    private int soul = 0;

    // -----------------------------------------------------------------------
    // Invulnerabilità
    // -----------------------------------------------------------------------
    private static final float INVULN_DURATION = 1.5f;
    private static final float FLASH_INTERVAL  = 0.08f;
    private boolean invulnerable = false;
    private float   invulnTimer  = 0f;
    private float   flashTimer   = 0f;
    private boolean flashVisible = true;

    // -----------------------------------------------------------------------
    // Hitstop
    // -----------------------------------------------------------------------
    private static final float HITSTOP_DURATION = 0.12f;
    private float   hitstopTimer = 0f;
    private boolean hitstopActive = false;

    // -----------------------------------------------------------------------
    // Dash
    // -----------------------------------------------------------------------
    private static final float DASH_SPEED     = 520f;
    private static final float DASH_DURATION  = 0.18f;
    private static final float DASH_COOLDOWN  = 0.6f;
    private float dashTimer    = 0f;
    private float dashCooldown = 0f;
    private float dashDir      = 1f;
    private Animation dashAnim;

    // -----------------------------------------------------------------------
    // Doppio salto
    // -----------------------------------------------------------------------
    private boolean canDoubleJump  = false;
    private boolean doubleJumpUsed = false;

    private Animation jumpUp;
    private Animation jumpLand;
    private Animation frameRise1, frameRise2, frameAltezzaMax, frameDrop1, frameDrop2;

    private float jumpSpeed;
    private BaseActor belowSensor;

    private Playerstate currentState;
    private boolean wasOnSolid = true;

    private float jumpTimer   = 0;
    private float totalJumpTime;

    private Animation attack;
    private Animation healAnim;
    private boolean   healApplied = false;

    // -----------------------------------------------------------------------
    // SFX flag
    // -----------------------------------------------------------------------
    private boolean landSoundPlayed   = false;
    private boolean attackSoundPlayed = false;

    // -----------------------------------------------------------------------
    // Spawn / respawn
    // -----------------------------------------------------------------------
    private float spawnX;
    private float spawnY;
    private static final float VOID_Y = -300f;

    // -----------------------------------------------------------------------
    // Transizione mappa
    // Quando true, boundToWorld() non blocca Pablo sui bordi X,
    // permettendogli di uscire dalla mappa e innescare una transizione.
    // -----------------------------------------------------------------------
    private boolean allowMapTransition = false;

    // -----------------------------------------------------------------------
    // Costruttore
    // -----------------------------------------------------------------------
    public Pablo(float x, float y, Stage s)
    {
        super(x, y, s);

        this.spawnX = x;
        this.spawnY = y;

        currentState = Playerstate.IDLE;

        stand = loadTexture("assets/Pablo/stand.png");

        String[] walkFile = {
                "assets/Pablo/walk1.png","assets/Pablo/walk2.png","assets/Pablo/walk3.png",
                "assets/Pablo/walk4.png","assets/Pablo/walk5.png","assets/Pablo/walk6.png",
                "assets/Pablo/walk7.png","assets/Pablo/walk8.png","assets/Pablo/walk9.png"
        };
        walk = loadAnimationFromFiles(walkFile, 0.10f, true);

        maxHorizontalSpeed = 200;
        walkAcceleration   = 200;
        walkDeceleration   = 200;
        gravity            = 500;
        maxVerticalSpeed   = 1000;
        jumpSpeed          = 400;

        maxHealth = 5;
        health    = maxHealth;

        totalJumpTime = (jumpSpeed / gravity) * 2.0f;

        String[] upFiles = {"assets/Pablo/jump1.png","assets/Pablo/jump2.png","assets/Pablo/jump3.png"};
        jumpUp = loadAnimationFromFiles(upFiles, (totalJumpTime * 0.10f) / 3f, false);

        String[] landFiles = {"assets/Pablo/jump9.png","assets/Pablo/jump10.png"};
        jumpLand = loadAnimationFromFiles(landFiles, (totalJumpTime * 0.10f) / 2f, false);

        frameRise1      = loadTexture("assets/Pablo/jump4.png");
        frameRise2      = loadTexture("assets/Pablo/jump5.png");
        frameAltezzaMax = loadTexture("assets/Pablo/jump6.png");
        frameDrop1      = loadTexture("assets/Pablo/jump7.png");
        frameDrop2      = loadTexture("assets/Pablo/jump8.png");

        setBoundaryPolygon(6);
        belowSensor = new BaseActor(0, 0, s);
        // belowSensor.loadTexture("assets/white.png");
        belowSensor.setSize(this.getWidth() - 8, 8);
        belowSensor.setBoundaryRectangle();
        // belowSensor.setVisible(true);

        String[] attackFile = {
                "assets/Pablo/attack3.png","assets/Pablo/attack10.png",
                "assets/Pablo/attack8.png","assets/Pablo/attack9.png"
        };
        attack = loadAnimationFromFiles(attackFile, 0.06f, false);
        attack.setPlayMode(Animation.PlayMode.NORMAL);

        String[] healFiles = {
                "assets/Pablo/heal1.png","assets/Pablo/heal2.png",
                "assets/Pablo/heal3.png","assets/Pablo/heal4.png",
                "assets/Pablo/heal5.png","assets/Pablo/heal6.png"
        };
        healAnim = loadAnimationFromFiles(healFiles, 0.10f, false);
        healAnim.setPlayMode(Animation.PlayMode.NORMAL);

        String[] dashFiles = {
                "assets/Pablo/dash1.png","assets/Pablo/dash2.png",
                "assets/Pablo/dash3.png","assets/Pablo/dash4.png",
                "assets/Pablo/dash5.png"
        };
        boolean dashAssetsDisponibili = true;
        for (String fileName : dashFiles)
            if (!Gdx.files.internal(fileName).exists()) { dashAssetsDisponibili = false; break; }

        if (dashAssetsDisponibili)
        {
            dashAnim = loadAnimationFromFiles(dashFiles, DASH_DURATION / 5f, false);
            dashAnim.setPlayMode(Animation.PlayMode.NORMAL);
        }
        else
        {
            dashAnim = stand;
        }
    }

    // -----------------------------------------------------------------------
    // act()
    // -----------------------------------------------------------------------
    public void act(float dt)
    {
        super.act(dt);

        SoundManager.get().update(dt);

        if (hitstopActive)
        {
            hitstopTimer -= dt;
            if (hitstopTimer <= 0f) hitstopActive = false;
            else return;
        }

        boolean onSolid = isOnSolid();

        if (invulnerable)
        {
            invulnTimer -= dt;
            flashTimer  -= dt;
            if (flashTimer <= 0f) { flashVisible = !flashVisible; setVisible(flashVisible); flashTimer = FLASH_INTERVAL; }
            if (invulnTimer <= 0f) { invulnerable = false; setVisible(true); }
        }

        if (dashCooldown > 0f) dashCooldown -= dt;

        if (onSolid && !wasOnSolid)
        {
            doubleJumpUsed = false;
            if (!landSoundPlayed) { SoundManager.get().playSfx(Sfx.PLAYER_LAND); landSoundPlayed = true; }
        }
        if (!onSolid) landSoundPlayed = false;

        // Fisica
        if (currentState != Playerstate.ATTACKING && currentState != Playerstate.HEALING && currentState != Playerstate.DASHING)
        {
            if (Gdx.input.isKeyPressed(Input.Keys.LEFT)  || Gdx.input.isKeyPressed(Input.Keys.A)) accelerationVec.add(-walkAcceleration, 0);
            if (Gdx.input.isKeyPressed(Input.Keys.RIGHT) || Gdx.input.isKeyPressed(Input.Keys.D)) accelerationVec.add(walkAcceleration, 0);
        }

        accelerationVec.add(0, -gravity);
        velocityVec.add(accelerationVec.x * dt, accelerationVec.y * dt);

        if (!Gdx.input.isKeyPressed(Input.Keys.RIGHT) && !Gdx.input.isKeyPressed(Input.Keys.LEFT) &&
                !Gdx.input.isKeyPressed(Input.Keys.D)     && !Gdx.input.isKeyPressed(Input.Keys.A))
        {
            float dec = walkDeceleration * dt;
            float dir = (velocityVec.x > 0) ? 1 : -1;
            float spd = Math.abs(velocityVec.x) - dec;
            if (spd < 0) spd = 0;
            velocityVec.x = spd * dir;
        }

        velocityVec.x = MathUtils.clamp(velocityVec.x, -maxHorizontalSpeed, maxHorizontalSpeed);
        velocityVec.y = MathUtils.clamp(velocityVec.y, -maxVerticalSpeed,    maxVerticalSpeed);

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        accelerationVec.set(0, 0);

        belowSensor.setPosition(getX() + 4, getY() - 8);

        // State machine
        switch (currentState)
        {
            case IDLE:
            case WALKING:
                attackSoundPlayed = false;

                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if (Gdx.input.isKeyJustPressed(Input.Keys.F) && soul >= SOUL_PER_HEAL && health < maxHealth)
                {
                    soul -= SOUL_PER_HEAL; currentState = Playerstate.HEALING; elapsedTime = 0; healApplied = false;
                    SoundManager.get().playSfx(Sfx.PLAYER_HEAL_START); break;
                }
                if (Gdx.input.isButtonPressed(Input.Buttons.LEFT) || Gdx.input.isKeyJustPressed(Input.Keys.J))
                {
                    currentState = Playerstate.ATTACKING; elapsedTime = 0; spawnAttackHitbox();
                    SoundManager.get().playSfx(Sfx.PLAYER_ATTACK); break;
                }
                if (Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W))
                    if (onSolid) { jump(false); break; }
                if (wasOnSolid && !onSolid) { currentState = Playerstate.FALLING; jumpTimer = totalJumpTime * 0.55f; canDoubleJump = true; break; }
                currentState = (Math.abs(velocityVec.x) > 1f) ? Playerstate.WALKING : Playerstate.IDLE;
                setAnimation(currentState == Playerstate.WALKING ? walk : stand);
                break;

            case DASHING:
                dashTimer -= dt; setAnimation(dashAnim);
                velocityVec.x = DASH_SPEED * dashDir; velocityVec.y = 0;
                if (dashTimer <= 0f) { velocityVec.x = maxHorizontalSpeed * dashDir * 0.5f; currentState = onSolid ? Playerstate.IDLE : Playerstate.FALLING; dashCooldown = DASH_COOLDOWN; }
                break;

            case HEALING:
                setAnimation(healAnim); velocityVec.x = 0;
                if (!healApplied && healAnim.isAnimationFinished(elapsedTime)) { heal(1); healApplied = true; SoundManager.get().playSfx(Sfx.PLAYER_HEAL_END); }
                if (healAnim.isAnimationFinished(elapsedTime)) currentState = !onSolid ? Playerstate.FALLING : Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;

            case JUMPING:
                jumpTimer += dt;
                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if ((Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W)) && canDoubleJump && !doubleJumpUsed) { jump(true); break; }
                if (velocityVec.y <= 0) { currentState = Playerstate.FALLING; break; }
                if (onSolid && !wasOnSolid) { currentState = Playerstate.LANDING; elapsedTime = 0; jumpTimer = 0; break; }
                updateJumpAnimation();
                break;

            case FALLING:
                jumpTimer += dt;
                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if ((Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W)) && canDoubleJump && !doubleJumpUsed) { jump(true); break; }
                if (onSolid && !wasOnSolid) { currentState = Playerstate.LANDING; elapsedTime = 0; jumpTimer = 0; break; }
                updateJumpAnimation();
                break;

            case LANDING:
                setAnimation(jumpLand);
                if (jumpLand.isAnimationFinished(elapsedTime)) currentState = Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;

            case ATTACKING:
                setAnimation(attack);
                if (attack.isAnimationFinished(elapsedTime)) currentState = !onSolid ? Playerstate.FALLING : Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;
        }

        // Direzione sprite
        if (currentState != Playerstate.ATTACKING && currentState != Playerstate.HEALING && currentState != Playerstate.DASHING)
        {
            if (velocityVec.x > 0) setScaleX(1);
            if (velocityVec.x < 0) setScaleX(-1);
        }

        wasOnSolid = onSolid;
        // belowSensor.setColor(onSolid ? Color.GREEN : Color.RED);

        alignCamera();
        boundToWorld();
    }

    // -----------------------------------------------------------------------
    // boundToWorld() — override: salta il clamp X se le transizioni sono abilitate
    // -----------------------------------------------------------------------
    @Override
    public void boundToWorld()
    {
        // Clamp X solo se non siamo in modalità transizione mappa
        if (!allowMapTransition)
        {
            if (getX() < 0) setX(0);
            if (getX() + getWidth() > worldBounds.width) setX(worldBounds.width - getWidth());
        }

        // Clamp Y sempre (il void viene gestito da LevelScreen)
        if (getY() < 0) setY(0);
        if (getY() + getHeight() > worldBounds.height) setY(worldBounds.height - getHeight());
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------
    private void startDash()
    {
        dashDir = getScaleX() > 0 ? 1f : -1f; dashTimer = DASH_DURATION;
        currentState = Playerstate.DASHING; elapsedTime = 0;
        invulnerable = true; invulnTimer = DASH_DURATION; flashTimer = FLASH_INTERVAL; flashVisible = true;
        SoundManager.get().playSfx(Sfx.PLAYER_DASH);
    }

    private void jump(boolean isDoubleJump)
    {
        velocityVec.y = jumpSpeed; currentState = Playerstate.JUMPING; jumpTimer = 0; elapsedTime = 0;
        if (!isDoubleJump) { canDoubleJump = true; doubleJumpUsed = false; }
        else { doubleJumpUsed = true; }
        SoundManager.get().playSfx(Sfx.PLAYER_JUMP, isDoubleJump ? 1.15f : 1.0f);
    }

    public void jump() { jump(false); }

    private void updateJumpAnimation()
    {
        float p = jumpTimer / totalJumpTime;
        if      (p < 0.10f) setAnimation(jumpUp);
        else if (p < 0.50f) { float r = (p - 0.10f) / 0.40f; setAnimation(r < 0.40f ? frameRise1 : r < 0.80f ? frameRise2 : frameAltezzaMax); }
        else if (p < 0.90f) { float d = (p - 0.50f) / 0.40f; setAnimation(d < 0.20f ? frameAltezzaMax : d < 0.60f ? frameDrop1 : frameDrop2); }
        else setAnimation(frameDrop2);
    }

    private void spawnAttackHitbox()
    {
        float hitboxWidth  = 40f, hitboxHeight = 30f;
        float hitboxY = getY() + getHeight() / 2f - hitboxHeight / 2f;
        float hitboxX = (getScaleX() > 0) ? getX() + getWidth() : getX() - hitboxWidth;
        new Hitbox(hitboxX, hitboxY, hitboxWidth, hitboxHeight, 10, 0.05f, getStage(), () -> gainSoul(11));
    }

    public boolean belowOverlaps(BaseActor actor) { return belowSensor.overlaps(actor); }

    public boolean isOnSolid()
    {
        for (BaseActor actor : BaseActor.getList(getStage(), Object.class.getName()))
        {
            Object solid = (Object) actor;
            if (belowOverlaps(solid) && solid.isEnable()) return true;
        }
        return false;
    }

    // -----------------------------------------------------------------------
    // HP e danno
    // -----------------------------------------------------------------------
    public void takeDamage(int amount)
    {
        if (isDead || invulnerable) return;
        if (currentState == Playerstate.HEALING) { currentState = Playerstate.IDLE; healApplied = false; }
        health -= amount;
        if (health <= 0)
        {
            health = 0; isDead = true; setVisible(true);
            SoundManager.get().playSfx(Sfx.PLAYER_DEATH);
        }
        else
        {
            SoundManager.get().playSfx(Sfx.PLAYER_HURT);
            hitstopActive = true; hitstopTimer = HITSTOP_DURATION;
            invulnerable = true; invulnTimer = INVULN_DURATION; flashTimer = FLASH_INTERVAL; flashVisible = true;
        }
    }

    public void heal(int amount) { health = Math.min(health + amount, maxHealth); }

    public void respawn()
    {
        setPosition(spawnX, spawnY);
        velocityVec.set(0, 0); accelerationVec.set(0, 0);
        currentState = Playerstate.FALLING; jumpTimer = 0; elapsedTime = 0; wasOnSolid = false;
        invulnerable = false; hitstopActive = false; invulnTimer = 0; flashTimer = 0; flashVisible = true; setVisible(true);
        health = maxHealth; isDead = false;
    }

    public boolean isInVoid() { return getY() < VOID_Y || (getY() <= 0f && velocityVec.y < 0f && !isOnSolid()); }

    // -----------------------------------------------------------------------
    // Anima
    // -----------------------------------------------------------------------
    public void gainSoul(int amount)
    {
        int prev = soul;
        soul = Math.min(soul + amount, MAX_SOUL);
        if (soul > prev) SoundManager.get().playSfx(Sfx.PLAYER_SOUL_GAIN);
    }

    public void setSoul(int amount)  { soul = MathUtils.clamp(amount, 0, MAX_SOUL); }

    // -----------------------------------------------------------------------
    // Getter / Setter
    // -----------------------------------------------------------------------
    public int     getSoul()          { return soul; }
    public int     getMaxSoul()       { return MAX_SOUL; }
    public boolean isInvulnerable()   { return invulnerable; }
    public boolean isDead()           { return isDead; }
    public int     getHealth()        { return health; }
    public void setHealth(int h)
    {
        health = MathUtils.clamp(h, 0, maxHealth);
        isDead = (health <= 0);
    }
    public int     getMaxHealth()     { return maxHealth; }

    /**
     * Imposta gli HP direttamente — usato da PlayerState.applyTo()
     * per ripristinare la salute dopo una transizione di mappa.
     */


    /**
     * Abilita o disabilita la possibilità di uscire dai bordi X della mappa.
     * Va abilitato solo quando la mappa ha vicini registrati in MapGraph.
     */
    public void setAllowMapTransition(boolean allow)
    {
        allowMapTransition = allow;
    }
}

// Pablo.java

package pablo.entities.player;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.Input;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.g2d.Animation;
import com.badlogic.gdx.math.MathUtils;
import com.badlogic.gdx.scenes.scene2d.Stage;
import pablo.Object;
import pablo.SoundManager;
import pablo.SoundManager.Sfx;
import pablo.framework.BaseActor;
import pablo.entities.combat.Hitbox;

public class Pablo extends BaseActor
{
    private Animation stand;
    private Animation walk;

    private float walkAcceleration;
    private float walkDeceleration;
    private float maxHorizontalSpeed;
    private float gravity;
    private float maxVerticalSpeed;

    // Health
    private int maxHealth;
    private int health;
    private boolean isDead = false;

    // Anima
    public  static final int MAX_SOUL      = 100;
    private static final int SOUL_PER_HEAL = 33;
    private int soul = 0;

    // -----------------------------------------------------------------------
    // Invulnerabilità
    // -----------------------------------------------------------------------
    private static final float INVULN_DURATION = 1.5f;
    private static final float FLASH_INTERVAL  = 0.08f;
    private boolean invulnerable = false;
    private float   invulnTimer  = 0f;
    private float   flashTimer   = 0f;
    private boolean flashVisible = true;

    // -----------------------------------------------------------------------
    // Hitstop
    // -----------------------------------------------------------------------
    private static final float HITSTOP_DURATION = 0.12f;
    private float   hitstopTimer = 0f;
    private boolean hitstopActive = false;

    // -----------------------------------------------------------------------
    // Dash
    // -----------------------------------------------------------------------
    private static final float DASH_SPEED     = 520f;
    private static final float DASH_DURATION  = 0.18f;
    private static final float DASH_COOLDOWN  = 0.6f;
    private float dashTimer    = 0f;
    private float dashCooldown = 0f;
    private float dashDir      = 1f;
    private Animation dashAnim;

    // -----------------------------------------------------------------------
    // Doppio salto
    // -----------------------------------------------------------------------
    private boolean canDoubleJump  = false;
    private boolean doubleJumpUsed = false;

    private Animation jumpUp;
    private Animation jumpLand;
    private Animation frameRise1, frameRise2, frameAltezzaMax, frameDrop1, frameDrop2;

    private float jumpSpeed;
    private BaseActor belowSensor;

    private Playerstate currentState;
    private boolean wasOnSolid = true;

    private float jumpTimer   = 0;
    private float totalJumpTime;

    private Animation attack;
    private Animation healAnim;
    private boolean   healApplied = false;

    // -----------------------------------------------------------------------
    // SFX flag
    // -----------------------------------------------------------------------
    private boolean landSoundPlayed   = false;
    private boolean attackSoundPlayed = false;

    // -----------------------------------------------------------------------
    // Spawn / respawn
    // -----------------------------------------------------------------------
    private float spawnX;
    private float spawnY;
    private static final float VOID_Y = -300f;

    // -----------------------------------------------------------------------
    // Transizione mappa
    // Quando true, boundToWorld() non blocca Pablo sui bordi X,
    // permettendogli di uscire dalla mappa e innescare una transizione.
    // -----------------------------------------------------------------------
    private boolean allowMapTransition = false;

    // -----------------------------------------------------------------------
    // Costruttore
    // -----------------------------------------------------------------------
    public Pablo(float x, float y, Stage s)
    {
        super(x, y, s);

        this.spawnX = x;
        this.spawnY = y;

        currentState = Playerstate.IDLE;

        stand = loadTexture("assets/Pablo/stand.png");

        String[] walkFile = {
                "assets/Pablo/walk1.png","assets/Pablo/walk2.png","assets/Pablo/walk3.png",
                "assets/Pablo/walk4.png","assets/Pablo/walk5.png","assets/Pablo/walk6.png",
                "assets/Pablo/walk7.png","assets/Pablo/walk8.png","assets/Pablo/walk9.png"
        };
        walk = loadAnimationFromFiles(walkFile, 0.10f, true);

        maxHorizontalSpeed = 200;
        walkAcceleration   = 200;
        walkDeceleration   = 200;
        gravity            = 500;
        maxVerticalSpeed   = 1000;
        jumpSpeed          = 400;

        maxHealth = 5;
        health    = maxHealth;

        totalJumpTime = (jumpSpeed / gravity) * 2.0f;

        String[] upFiles = {"assets/Pablo/jump1.png","assets/Pablo/jump2.png","assets/Pablo/jump3.png"};
        jumpUp = loadAnimationFromFiles(upFiles, (totalJumpTime * 0.10f) / 3f, false);

        String[] landFiles = {"assets/Pablo/jump9.png","assets/Pablo/jump10.png"};
        jumpLand = loadAnimationFromFiles(landFiles, (totalJumpTime * 0.10f) / 2f, false);

        frameRise1      = loadTexture("assets/Pablo/jump4.png");
        frameRise2      = loadTexture("assets/Pablo/jump5.png");
        frameAltezzaMax = loadTexture("assets/Pablo/jump6.png");
        frameDrop1      = loadTexture("assets/Pablo/jump7.png");
        frameDrop2      = loadTexture("assets/Pablo/jump8.png");

        setBoundaryPolygon(6);
        belowSensor = new BaseActor(0, 0, s);
        // belowSensor.loadTexture("assets/white.png");
        belowSensor.setSize(this.getWidth() - 8, 8);
        belowSensor.setBoundaryRectangle();
        // belowSensor.setVisible(true);

        String[] attackFile = {
                "assets/Pablo/attack3.png","assets/Pablo/attack10.png",
                "assets/Pablo/attack8.png","assets/Pablo/attack9.png"
        };
        attack = loadAnimationFromFiles(attackFile, 0.06f, false);
        attack.setPlayMode(Animation.PlayMode.NORMAL);

        String[] healFiles = {
                "assets/Pablo/heal1.png","assets/Pablo/heal2.png",
                "assets/Pablo/heal3.png","assets/Pablo/heal4.png",
                "assets/Pablo/heal5.png","assets/Pablo/heal6.png"
        };
        healAnim = loadAnimationFromFiles(healFiles, 0.10f, false);
        healAnim.setPlayMode(Animation.PlayMode.NORMAL);

        String[] dashFiles = {
                "assets/Pablo/dash1.png","assets/Pablo/dash2.png",
                "assets/Pablo/dash3.png","assets/Pablo/dash4.png",
                "assets/Pablo/dash5.png"
        };
        boolean dashAssetsDisponibili = true;
        for (String fileName : dashFiles)
            if (!Gdx.files.internal(fileName).exists()) { dashAssetsDisponibili = false; break; }

        if (dashAssetsDisponibili)
        {
            dashAnim = loadAnimationFromFiles(dashFiles, DASH_DURATION / 5f, false);
            dashAnim.setPlayMode(Animation.PlayMode.NORMAL);
        }
        else
        {
            dashAnim = stand;
        }
    }

    // -----------------------------------------------------------------------
    // act()
    // -----------------------------------------------------------------------
    public void act(float dt)
    {
        super.act(dt);

        SoundManager.get().update(dt);

        if (hitstopActive)
        {
            hitstopTimer -= dt;
            if (hitstopTimer <= 0f) hitstopActive = false;
            else return;
        }

        boolean onSolid = isOnSolid();

        if (invulnerable)
        {
            invulnTimer -= dt;
            flashTimer  -= dt;
            if (flashTimer <= 0f) { flashVisible = !flashVisible; setVisible(flashVisible); flashTimer = FLASH_INTERVAL; }
            if (invulnTimer <= 0f) { invulnerable = false; setVisible(true); }
        }

        if (dashCooldown > 0f) dashCooldown -= dt;

        if (onSolid && !wasOnSolid)
        {
            doubleJumpUsed = false;
            if (!landSoundPlayed) { SoundManager.get().playSfx(Sfx.PLAYER_LAND); landSoundPlayed = true; }
        }
        if (!onSolid) landSoundPlayed = false;

        // Fisica
        if (currentState != Playerstate.ATTACKING && currentState != Playerstate.HEALING && currentState != Playerstate.DASHING)
        {
            if (Gdx.input.isKeyPressed(Input.Keys.LEFT)  || Gdx.input.isKeyPressed(Input.Keys.A)) accelerationVec.add(-walkAcceleration, 0);
            if (Gdx.input.isKeyPressed(Input.Keys.RIGHT) || Gdx.input.isKeyPressed(Input.Keys.D)) accelerationVec.add(walkAcceleration, 0);
        }

        accelerationVec.add(0, -gravity);
        velocityVec.add(accelerationVec.x * dt, accelerationVec.y * dt);

        if (!Gdx.input.isKeyPressed(Input.Keys.RIGHT) && !Gdx.input.isKeyPressed(Input.Keys.LEFT) &&
                !Gdx.input.isKeyPressed(Input.Keys.D)     && !Gdx.input.isKeyPressed(Input.Keys.A))
        {
            float dec = walkDeceleration * dt;
            float dir = (velocityVec.x > 0) ? 1 : -1;
            float spd = Math.abs(velocityVec.x) - dec;
            if (spd < 0) spd = 0;
            velocityVec.x = spd * dir;
        }

        velocityVec.x = MathUtils.clamp(velocityVec.x, -maxHorizontalSpeed, maxHorizontalSpeed);
        velocityVec.y = MathUtils.clamp(velocityVec.y, -maxVerticalSpeed,    maxVerticalSpeed);

        moveBy(velocityVec.x * dt, velocityVec.y * dt);
        accelerationVec.set(0, 0);

        belowSensor.setPosition(getX() + 4, getY() - 8);

        // State machine
        switch (currentState)
        {
            case IDLE:
            case WALKING:
                attackSoundPlayed = false;

                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if (Gdx.input.isKeyJustPressed(Input.Keys.F) && soul >= SOUL_PER_HEAL && health < maxHealth)
                {
                    soul -= SOUL_PER_HEAL; currentState = Playerstate.HEALING; elapsedTime = 0; healApplied = false;
                    SoundManager.get().playSfx(Sfx.PLAYER_HEAL_START); break;
                }
                if (Gdx.input.isButtonPressed(Input.Buttons.LEFT) || Gdx.input.isKeyJustPressed(Input.Keys.J))
                {
                    currentState = Playerstate.ATTACKING; elapsedTime = 0; spawnAttackHitbox();
                    SoundManager.get().playSfx(Sfx.PLAYER_ATTACK); break;
                }
                if (Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W))
                    if (onSolid) { jump(false); break; }
                if (wasOnSolid && !onSolid) { currentState = Playerstate.FALLING; jumpTimer = totalJumpTime * 0.55f; canDoubleJump = true; break; }
                currentState = (Math.abs(velocityVec.x) > 1f) ? Playerstate.WALKING : Playerstate.IDLE;
                setAnimation(currentState == Playerstate.WALKING ? walk : stand);
                break;

            case DASHING:
                dashTimer -= dt; setAnimation(dashAnim);
                velocityVec.x = DASH_SPEED * dashDir; velocityVec.y = 0;
                if (dashTimer <= 0f) { velocityVec.x = maxHorizontalSpeed * dashDir * 0.5f; currentState = onSolid ? Playerstate.IDLE : Playerstate.FALLING; dashCooldown = DASH_COOLDOWN; }
                break;

            case HEALING:
                setAnimation(healAnim); velocityVec.x = 0;
                if (!healApplied && healAnim.isAnimationFinished(elapsedTime)) { heal(1); healApplied = true; SoundManager.get().playSfx(Sfx.PLAYER_HEAL_END); }
                if (healAnim.isAnimationFinished(elapsedTime)) currentState = !onSolid ? Playerstate.FALLING : Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;

            case JUMPING:
                jumpTimer += dt;
                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if ((Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W)) && canDoubleJump && !doubleJumpUsed) { jump(true); break; }
                if (velocityVec.y <= 0) { currentState = Playerstate.FALLING; break; }
                if (onSolid && !wasOnSolid) { currentState = Playerstate.LANDING; elapsedTime = 0; jumpTimer = 0; break; }
                updateJumpAnimation();
                break;

            case FALLING:
                jumpTimer += dt;
                if (Gdx.input.isKeyJustPressed(Input.Keys.SHIFT_LEFT) && dashCooldown <= 0f) { startDash(); break; }
                if ((Gdx.input.isKeyJustPressed(Input.Keys.SPACE) || Gdx.input.isKeyJustPressed(Input.Keys.W)) && canDoubleJump && !doubleJumpUsed) { jump(true); break; }
                if (onSolid && !wasOnSolid) { currentState = Playerstate.LANDING; elapsedTime = 0; jumpTimer = 0; break; }
                updateJumpAnimation();
                break;

            case LANDING:
                setAnimation(jumpLand);
                if (jumpLand.isAnimationFinished(elapsedTime)) currentState = Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;

            case ATTACKING:
                setAnimation(attack);
                if (attack.isAnimationFinished(elapsedTime)) currentState = !onSolid ? Playerstate.FALLING : Math.abs(velocityVec.x) > 1f ? Playerstate.WALKING : Playerstate.IDLE;
                break;
        }

        // Direzione sprite
        if (currentState != Playerstate.ATTACKING && currentState != Playerstate.HEALING && currentState != Playerstate.DASHING)
        {
            if (velocityVec.x > 0) setScaleX(1);
            if (velocityVec.x < 0) setScaleX(-1);
        }

        wasOnSolid = onSolid;
        // belowSensor.setColor(onSolid ? Color.GREEN : Color.RED);

        alignCamera();
        boundToWorld();
    }

    // -----------------------------------------------------------------------
    // boundToWorld() — override: salta il clamp X se le transizioni sono abilitate
    // -----------------------------------------------------------------------
    @Override
    public void boundToWorld()
    {
        // Clamp X solo se non siamo in modalità transizione mappa
        if (!allowMapTransition)
        {
            if (getX() < 0) setX(0);
            if (getX() + getWidth() > worldBounds.width) setX(worldBounds.width - getWidth());
        }

        // Clamp Y sempre (il void viene gestito da LevelScreen)
        if (getY() < 0) setY(0);
        if (getY() + getHeight() > worldBounds.height) setY(worldBounds.height - getHeight());
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------
    private void startDash()
    {
        dashDir = getScaleX() > 0 ? 1f : -1f; dashTimer = DASH_DURATION;
        currentState = Playerstate.DASHING; elapsedTime = 0;
        invulnerable = true; invulnTimer = DASH_DURATION; flashTimer = FLASH_INTERVAL; flashVisible = true;
        SoundManager.get().playSfx(Sfx.PLAYER_DASH);
    }

    private void jump(boolean isDoubleJump)
    {
        velocityVec.y = jumpSpeed; currentState = Playerstate.JUMPING; jumpTimer = 0; elapsedTime = 0;
        if (!isDoubleJump) { canDoubleJump = true; doubleJumpUsed = false; }
        else { doubleJumpUsed = true; }
        SoundManager.get().playSfx(Sfx.PLAYER_JUMP, isDoubleJump ? 1.15f : 1.0f);
    }

    public void jump() { jump(false); }

    private void updateJumpAnimation()
    {
        float p = jumpTimer / totalJumpTime;
        if      (p < 0.10f) setAnimation(jumpUp);
        else if (p < 0.50f) { float r = (p - 0.10f) / 0.40f; setAnimation(r < 0.40f ? frameRise1 : r < 0.80f ? frameRise2 : frameAltezzaMax); }
        else if (p < 0.90f) { float d = (p - 0.50f) / 0.40f; setAnimation(d < 0.20f ? frameAltezzaMax : d < 0.60f ? frameDrop1 : frameDrop2); }
        else setAnimation(frameDrop2);
    }

    private void spawnAttackHitbox()
    {
        spawnAttackHitbox(false);
    }

    private void spawnAttackHitbox(boolean downStrike)
    {
        float hitboxWidth  = 40f, hitboxHeight = 30f;
        float hitboxY = getY() + getHeight() / 2f - hitboxHeight / 2f;
        float hitboxX = (getScaleX() > 0) ? getX() + getWidth() : getX() - hitboxWidth;

        if (downStrike)
        {
            hitboxWidth = 30f; hitboxHeight = 40f;
            hitboxX = getX() + getWidth() / 2f - hitboxWidth / 2f;
            hitboxY = getY() - hitboxHeight;
            new Hitbox(hitboxX, hitboxY, hitboxWidth, hitboxHeight, 10, 0.05f, getStage(), () -> {
                gainSoul(11);
                // Pogo leap
                velocityVec.y = jumpSpeed * 0.85f;
                canDoubleJump = true;
                doubleJumpUsed = false;
                currentState = Playerstate.JUMPING;
            });
        }
        else
        {
            new Hitbox(hitboxX, hitboxY, hitboxWidth, hitboxHeight, 10, 0.05f, getStage(), () -> gainSoul(11));
        }
    }

    public boolean belowOverlaps(BaseActor actor) { return belowSensor.overlaps(actor); }

    public boolean isOnSolid()
    {
        for (BaseActor actor : BaseActor.getList(getStage(), Object.class.getName()))
        {
            Object solid = (Object) actor;
            if (belowOverlaps(solid) && solid.isEnable()) return true;
        }
        return false;
    }

    // -----------------------------------------------------------------------
    // HP e danno
    // -----------------------------------------------------------------------
    public void takeDamage(int amount)
    {
        if (isDead || invulnerable) return;
        if (currentState == Playerstate.HEALING) { currentState = Playerstate.IDLE; healApplied = false; }
        health -= amount;
        if (health <= 0)
        {
            health = 0; isDead = true; setVisible(true);
            SoundManager.get().playSfx(Sfx.PLAYER_DEATH);
        }
        else
        {
            SoundManager.get().playSfx(Sfx.PLAYER_HURT);
            hitstopActive = true; hitstopTimer = HITSTOP_DURATION;
            invulnerable = true; invulnTimer = INVULN_DURATION; flashTimer = FLASH_INTERVAL; flashVisible = true;
        }
    }

    public void heal(int amount) { health = Math.min(health + amount, maxHealth); }

    public void respawn()
    {
        setPosition(spawnX, spawnY);
        velocityVec.set(0, 0); accelerationVec.set(0, 0);
        currentState = Playerstate.FALLING; jumpTimer = 0; elapsedTime = 0; wasOnSolid = false;
        invulnerable = false; hitstopActive = false; invulnTimer = 0; flashTimer = 0; flashVisible = true; setVisible(true);
        health = maxHealth; isDead = false;
    }

    public boolean isInVoid() { return getY() < VOID_Y || (getY() <= 0f && velocityVec.y < 0f && !isOnSolid()); }

    // -----------------------------------------------------------------------
    // Anima
    // -----------------------------------------------------------------------
    public void gainSoul(int amount)
    {
        int prev = soul;
        soul = Math.min(soul + amount, MAX_SOUL);
        if (soul > prev) SoundManager.get().playSfx(Sfx.PLAYER_SOUL_GAIN);
    }

    public void setSoul(int amount)  { soul = MathUtils.clamp(amount, 0, MAX_SOUL); }

    // -----------------------------------------------------------------------
    // Getter / Setter
    // -----------------------------------------------------------------------
    public int     getSoul()          { return soul; }
    public int     getMaxSoul()       { return MAX_SOUL; }
    public boolean isInvulnerable()   { return invulnerable; }
    public boolean isDead()           { return isDead; }
    public int     getHealth()        { return health; }
    public void setHealth(int h)
    {
        health = MathUtils.clamp(h, 0, maxHealth);
        isDead = (health <= 0);
    }
    public int     getMaxHealth()     { return maxHealth; }

    /**
     * Imposta gli HP direttamente — usato da PlayerState.applyTo()
     * per ripristinare la salute dopo una transizione di mappa.
     */


    /**
     * Abilita o disabilita la possibilità di uscire dai bordi X della mappa.
     * Va abilitato solo quando la mappa ha vicini registrati in MapGraph.
     */
    public void setAllowMapTransition(boolean allow)
    {
        allowMapTransition = allow;
    }
}

